interface LauncherTileProps {
    id: string;
    label: string;
    icon: React.ReactNode;
    isForcedLock?: boolean;
    badgeCount?: number;
    badgeColor?: string;
    isInspectionModule?: boolean;
    isLocked: boolean;
    isAd?: boolean;
    onNavigate: (module: string) => void;
    compact?: boolean;
}

const LauncherTile = ({ 
    id, label, icon, isForcedLock = false, badgeCount = 0, badgeColor = 'bg-slate-900', 
    isInspectionModule = false, isLocked, isAd = false, onNavigate, compact = false
}: LauncherTileProps) => {
    const effectiveLock = isForcedLock || (isInspectionModule && isLocked);

    const handleTileClick = () => {
        if (isAd) {
            onNavigate(`support:info:${label}`);
            return;
        }
        if (!effectiveLock) {
            onNavigate(id);
        }
    };

    return (
        <button 
            onClick={handleTileClick}
            className={`flex flex-col items-center justify-center transition-all w-full group relative 
                ${compact ? 'p-2' : 'p-3 sm:p-5'}
                ${isAd 
                    ? 'opacity-80 hover:opacity-100 cursor-pointer active:scale-95' 
                    : effectiveLock 
                        ? 'opacity-25 cursor-not-allowed grayscale' 
                        : 'hover:opacity-60 active:scale-95'
                }`}
        >
            <div className={`relative ${compact ? 'mb-2' : 'mb-4 sm:mb-6'}`}>
                {icon}
                {effectiveLock && !isAd && (
                    <div className="absolute -top-1 -right-1 bg-slate-900 text-white rounded-full p-1 shadow-sm border border-white">
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                    </div>
                )}
                {badgeCount > 0 && !effectiveLock && (
                    <div className={`absolute -top-1.5 -right-1.5 ${badgeColor} text-white text-[8px] font-black w-4 h-4 rounded-full flex items-center justify-center border-2 border-white shadow-sm z-20 animate-fadeIn`}>
                        {badgeCount}
                    </div>
                )}
            </div>
            <span className={`font-medium text-center tracking-[0.1em] leading-tight transition-colors w-full uppercase ${compact ? 'text-[8px]' : 'text-[9px] sm:text-[11px]'} ${effectiveLock && !isAd ? 'text-slate-300' : 'text-slate-500 group-hover:text-blue-600'}`}>
                {label}
            </span>
        </button>
    );
};

const SectionHeader = ({ label }: { label: string }) => (
    <div className="w-full flex items-center gap-6 mb-10 sm:mb-16 px-4 md:px-0">
        <span className="text-[9px] sm:text-[10px] font-semibold text-slate-400 tracking-[0.4em] whitespace-nowrap uppercase opacity-80">{label}</span>
