                        <LauncherTile id="track_requests" label="Requests" isLocked={isLocked} onNavigate={onNavigate} icon={<RequestsIcon />} />
                        <LauncherTile id="support" label="Support" isLocked={isLocked} onNavigate={onNavigate} icon={<SupportIcon />} />
                    </div>
                </section>
            </div>

            {/* FLOATING NETWORK HUB (Integrated Corporate Solutions) */}
            <div className="fixed bottom-6 right-6 z-50">
                {isNetworkOpen && (
                    <div className="absolute bottom-16 right-0 w-64 sm:w-80 bg-white/90 backdrop-blur-xl border border-slate-200 rounded-[2rem] shadow-2xl p-6 mb-2 animate-fadeIn origin-bottom-right">
                        <div className="flex items-center justify-between mb-6 px-2">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Network Services</span>
                            <div className="h-px flex-1 bg-slate-100 ml-4"></div>
                        </div>
                        <div className="grid grid-cols-3 gap-2">
                            <LauncherTile compact id="ad_maintenance" label="Maint" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<div className="w-8 h-8"><MaintenanceAppIcon /></div>} />
                            <LauncherTile compact id="ad_hr" label="Staff" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<div className="w-8 h-8"><StaffIcon /></div>} />
                            <LauncherTile compact id="ad_finance" label="Finance" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<div className="w-8 h-8"><FinanceTicketIcon /></div>} />
                            <LauncherTile compact id="ad_driver" label="Driver" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<div className="w-8 h-8"><DriverMgmtIcon /></div>} />
                            <LauncherTile compact id="ad_planning" label="Plan" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<div className="w-8 h-8"><PlanningIcon /></div>} />
                            <LauncherTile compact id="ad_incident" label="Incid" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<div className="w-8 h-8"><IncidentIcon /></div>} />
                        </div>
                    </div>
                )}

                <button 
                    onClick={() => setIsNetworkOpen(!isNetworkOpen)}
                    className={`w-14 h-14 rounded-2xl flex flex-col items-center justify-center transition-all duration-300 shadow-xl border-t border-white/20
                        ${isNetworkOpen ? 'bg-rose-500 text-white rotate-90' : 'bg-slate-900 text-white hover:bg-black'}
