interface LauncherTileProps {
    id: string;
    label: string;
    icon: React.ReactNode;
    isForcedLock?: boolean;
    badgeCount?: number;
    badgeColor?: string;
    isInspectionModule?: boolean;
    isLocked: boolean;
    isAd?: boolean;
    onNavigate: (module: string) => void;
    compact?: boolean;
}

const LauncherTile = ({ 
    id, label, icon, isForcedLock = false, badgeCount = 0, badgeColor = 'bg-slate-900', 
    isInspectionModule = false, isLocked, isAd = false, onNavigate, compact = false
}: LauncherTileProps) => {
    const effectiveLock = isForcedLock || (isInspectionModule && isLocked);

    const handleTileClick = () => {
        if (isAd) {
            onNavigate(`support:info:${label}`);
            return;
        }
        if (!effectiveLock) {
            onNavigate(id);
        }
    };

    return (
        <button 
            onClick={handleTileClick}
            className={`flex flex-col items-center justify-center transition-all w-full group relative 
                ${compact ? 'p-1' : 'p-4 sm:p-8'}
                ${isAd 
                    ? 'opacity-80 hover:opacity-100 cursor-pointer active:scale-95' 
                    : effectiveLock 
                        ? 'opacity-20 cursor-not-allowed grayscale' 
                        : 'hover:opacity-40 active:scale-95'
                }`}
        >
            <div className={`relative flex items-center justify-center ${compact ? 'mb-3' : 'mb-6 sm:mb-8'}`}>
                {icon}
                {effectiveLock && !isAd && (
                    <div className="absolute -top-1 -right-1 bg-slate-900 text-white rounded-full p-1.5 shadow-sm border border-white">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                    </div>
                )}
                {badgeCount > 0 && !effectiveLock && (
                    <div className={`absolute -top-2 -right-2 ${badgeColor} text-white text-[10px] font-black w-6 h-6 rounded-full flex items-center justify-center border-2 border-white shadow-lg z-20 animate-fadeIn`}>
                        {badgeCount}
                    </div>
                )}
            </div>
            <span className={`font-medium text-center tracking-tight leading-tight transition-all w-full uppercase ${compact ? 'text-[7px] sm:text-[9px]' : 'text-[9px] sm:text-[13px]'} ${effectiveLock && !isAd ? 'text-slate-300' : 'text-slate-500 group-hover:text-blue-600'}`}>
                {label}
            </span>
            {isAd && (
                <span className="text-[6px] font-black text-indigo-400 uppercase tracking-widest mt-1 opacity-0 group-hover:opacity-100 transition-opacity">Ready</span>
            )}
        </button>
    );
};

const SectionHeader = ({ label }: { label: string }) => (
    <div className="w-full flex items-center gap-6 sm:gap-10 mb-8 sm:mb-16 px-4 md:px-0">
        <span className="text-[10px] sm:text-[13px] font-semibold text-slate-300 uppercase tracking-[0.3em] sm:tracking-[0.5em] whitespace-nowrap">{label}</span>
        <div className="h-px flex-1 bg-slate-100"></div>
    </div>
);

const OverviewDashboard: React.FC<OverviewDashboardProps> = ({ onNavigate, userRole, isLocked = false, pendingAlertsCount = 0 }) => {
    const isAdmin = userRole === 'Admin' || userRole === 'SuperAdmin';
    const isSuperAdmin = userRole === 'SuperAdmin';
    const [isSuiteOpen, setIsSuiteOpen] = useState(false);

    return (
        <div className="max-w-6xl mx-auto py-8 sm:py-20 flex flex-col items-center justify-center min-h-[calc(100vh-160px)] px-4">
            <div className="w-full space-y-16 sm:space-y-32">

                {/* 1. System Management */}
                <section id="system-mgmt-section" className="w-full animate-fadeIn">
                    <SectionHeader label="System Management" />
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 sm:gap-12 md:gap-16">
                        <LauncherTile id="maintenance" label="Security" isLocked={isLocked} isForcedLock={!isSuperAdmin} onNavigate={onNavigate} icon={<SecurityIcon />} />
                        <LauncherTile id="users" label="Staff" isLocked={isLocked} isForcedLock={!isAdmin} onNavigate={onNavigate} icon={<StaffIcon />} />
                        <LauncherTile id="registry" label="Fleet Registry" isLocked={isLocked} isForcedLock={!isAdmin} onNavigate={onNavigate} icon={<RegistryIcon />} />
                        <LauncherTile id="settings" label="Settings" isLocked={isLocked} isForcedLock={!isAdmin} onNavigate={onNavigate} icon={<SettingsIcon />} />
                    </div>
                </section>

                {/* 2. Inspection Hub */}
                <section id="inspection-forms-section" className="w-full animate-fadeIn">
                    <SectionHeader label="Inspection Hub" />
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 sm:gap-12 md:gap-16">
                        <LauncherTile id="general" label="General Inspection" isInspectionModule={true} isLocked={isLocked} onNavigate={onNavigate} icon={<InspectionChecklistIcon />} />
                        <LauncherTile id="petroleum" label="Petroleum V1 Inspection" isInspectionModule={true} isLocked={isLocked} onNavigate={onNavigate} icon={<InspectionChecklistIcon />} />
                        <LauncherTile id="petroleum_v2" label="Petroleum V2 Inspection" isInspectionModule={true} isLocked={isLocked} onNavigate={onNavigate} icon={<InspectionChecklistIcon />} />
                        <LauncherTile id="acid" label="Acid Tanker Inspection" isInspectionModule={true} isLocked={isLocked} onNavigate={onNavigate} icon={<InspectionChecklistIcon />} />
                    </div>
                </section>

                {/* 3. Operations & Logistics */}
                <section className="w-full animate-fadeIn">
                    <SectionHeader label="Operations & Logistics" />
                    <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 sm:gap-12 md:gap-16">
                        <LauncherTile id="analytics" label="Fleet Analysis" isLocked={isLocked} onNavigate={onNavigate} icon={<AnalyticsIcon />} badgeCount={pendingAlertsCount} badgeColor="bg-rose-500" />
                        <LauncherTile id="track_requests" label="Request Inspection" isLocked={isLocked} onNavigate={onNavigate} icon={<RequestsIcon />} />
                        <LauncherTile id="support" label="Support Center" isLocked={isLocked} onNavigate={onNavigate} icon={<SupportIcon />} />
                    </div>
                </section>
            </div>

            {/* FLOATING SUITE HUB (Integrated Corporate Solutions) */}
            <div className="fixed bottom-6 right-6 sm:bottom-8 sm:right-8 z-50">
                {isSuiteOpen && (
                    <div className="absolute bottom-16 right-0 w-[calc(100vw-2.5rem)] sm:w-[460px] bg-white/95 backdrop-blur-3xl border border-white/40 rounded-[2rem] sm:rounded-[3rem] shadow-[0_32px_128px_-20px_rgba(15,23,42,0.3)] p-4 sm:p-12 mb-4 animate-fadeIn origin-bottom-right">
                        <div className="flex flex-col mb-8 text-center shrink-0">
                            <span className="text-[9px] sm:text-[10px] font-black text-indigo-500 uppercase tracking-[0.3em] mb-1 sm:mb-2">Integrated Corporate Solutions</span>
                            <div className="h-px w-16 sm:w-24 bg-indigo-100 mx-auto"></div>
                        </div>
                        <div className="grid grid-cols-3 gap-x-4 gap-y-6 sm:gap-8">
                            <LauncherTile compact id="ad_maintenance" label="Fleet Maintenance Software" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<MaintenanceAppIcon />} />
                            <LauncherTile compact id="ad_hr" label="HR & Payroll" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<SuiteStaffIcon />} />
                            <LauncherTile compact id="ad_finance" label="Finance Ticket Management" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<FinanceTicketIcon />} />
                            <LauncherTile compact id="ad_driver" label="Driver Management System" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<DriverMgmtIcon />} />
                            <LauncherTile compact id="ad_planning" label="Fleet Planning System" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<PlanningIcon />} />
                            <LauncherTile compact id="ad_incident" label="Incident Report System" isAd={true} isLocked={true} onNavigate={onNavigate} icon={<IncidentIcon />} />
                        </div>
                        <div className="mt-10 sm:mt-10 pt-4 sm:pt-8 border-t border-slate-100 text-center shrink-0">
                             <p className="text-[8px] sm:text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] sm:tracking-[0.3em]">Available as Modular Extensions</p>
                        </div>
                    </div>
                )}

                <button 
                    onClick={() => setIsSuiteOpen(!isSuiteOpen)}
                    className={`w-14 h-14 sm:w-20 sm:h-20 rounded-[1.5rem] sm:rounded-[2rem] flex flex-col items-center justify-center transition-all duration-500 shadow-2xl border-t border-white/30
                        ${isSuiteOpen ? 'bg-indigo-600 text-white rotate-90 scale-90' : 'bg-slate-900 text-white hover:bg-black hover:-translate-y-1'}
                    `}
                >
                    {isSuiteOpen ? (
                        <svg className="w-7 h-7 sm:w-10 sm:h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M6 18L18 6M6 6l12 12"></path></svg>
                    ) : (
                        <>
                            <svg className="w-6 h-6 sm:w-9 sm:h-9" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="1.8"><path d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                            <span className="text-[7px] sm:text-[10px] font-black uppercase tracking-tighter mt-1">Suite</span>
                        </>
                    )}
                </button>
            </div>
        </div>
    );
};

