                <button 
                    onClick={() => setIsSuiteOpen(!isSuiteOpen)}
                    className={`w-14 h-14 sm:w-20 sm:h-20 rounded-[1.5rem] sm:rounded-[2.2rem] flex flex-col items-center justify-center transition-all duration-700 shadow-[0_20px_50px_-10px_rgba(15,23,42,0.4)] border-t border-white/40
