interface LauncherTileProps {
    id: string;
    label: string;
    icon: React.ReactNode;
    isForcedLock?: boolean;
    badgeCount?: number;
    badgeColor?: string;
    isInspectionModule?: boolean;
    isLocked: boolean;
    isAd?: boolean;
    onNavigate: (module: string) => void;
    compact?: boolean;
}

const LauncherTile = ({ 
    id, label, icon, isForcedLock = false, badgeCount = 0, badgeColor = 'bg-slate-900', 
    isInspectionModule = false, isLocked, isAd = false, onNavigate, compact = false
}: LauncherTileProps) => {
    const effectiveLock = isForcedLock || (isInspectionModule && isLocked);

    const handleTileClick = () => {
        if (isAd) {
            onNavigate(`support:info:${label}`);
            return;
        }
        if (!effectiveLock) {
            onNavigate(id);
        }
    };

    return (
        <button 
            onClick={handleTileClick}
            className={`flex flex-col items-center justify-center transition-all w-full group relative 
                ${compact ? 'p-1' : 'p-4 sm:p-6'}
                ${isAd 
                    ? 'opacity-80 hover:opacity-100 cursor-pointer active:scale-95' 
                    : effectiveLock 
                        ? 'opacity-20 cursor-not-allowed grayscale' 
                        : 'hover:opacity-100 active:scale-95'
                }`}
        >
            <div className={`relative flex items-center justify-center transition-all duration-500 ${compact ? 'mb-2' : 'mb-6 sm:mb-4'} 
                ${!effectiveLock && !isAd ? 'bg-white group-hover:bg-indigo-50/30 rounded-[2.5rem] w-full aspect-square border border-transparent group-hover:border-indigo-100/50 group-hover:shadow-[0_15px_40px_-20px_rgba(79,70,229,0.12)]' : ''}`}
            >
                <div className="flex items-center justify-center w-full h-full relative z-10">
                    {icon}
                </div>
                {effectiveLock && !isAd && (
                    <div className="absolute -top-1 -right-1 bg-slate-900 text-white rounded-full p-1.5 shadow-sm border border-white z-20">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                    </div>
                )}
                {badgeCount > 0 && !effectiveLock && (
                    <div className={`absolute -top-2 -right-2 ${badgeColor} text-white text-[10px] font-black w-6 h-6 rounded-full flex items-center justify-center border-2 border-white shadow-lg z-20 animate-fadeIn`}>
                        {badgeCount}
                    </div>
                )}
            </div>
            <span className={`font-bold text-center tracking-[0.15em] leading-tight transition-all w-full uppercase ${compact ? 'text-[7px] sm:text-[9px]' : 'text-[9px] sm:text-[11px]'} ${effectiveLock && !isAd ? 'text-slate-300' : 'text-slate-400 group-hover:text-slate-900'}`}>
                {label}
            </span>
            {isAd && (
                <span className="text-[6px] font-black text-indigo-400 uppercase tracking-[0.3em] mt-2 opacity-0 group-hover:opacity-100 transition-all">Modular Extension</span>
            )}
        </button>
    );
};

