import React, { useState, useEffect, useMemo } from 'react';
import { User, SystemSettings, SubscriptionDetails } from '../types';

interface MaintenanceViewProps {
    user: User;
    appScriptUrl: string;
    settings: SystemSettings;
    onSettingsUpdate: (newSettings: Partial<SystemSettings>) => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    onRefreshSubscription?: () => void;
    subscription?: SubscriptionDetails | null;
    history?: any[];
}

const MaintenanceView: React.FC<MaintenanceViewProps> = ({ 
    user, appScriptUrl, settings, onSettingsUpdate, showToast, onRefreshSubscription, subscription, history = [] 
}) => {
    const [msgType, setMsgType] = useState<'info' | 'warning' | 'critical'>('info');
    const [msgBody, setMsgBody] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [maintMode, setMaintMode] = useState(settings.maintenanceMode || false);
    const [maintMessage, setMaintMessage] = useState(settings.maintenanceMessage || 'System under scheduled maintenance.');
    const [isSavingMaint, setIsSavingMaint] = useState(false);
    const [isSavingLicense, setIsSavingLicense] = useState(false);

    const handleBroadcast = async () => {
        if (!msgBody.trim()) { showToast("Enter alert message.", "error"); return; }
        setIsSending(true);
        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'broadcast', type: msgType, message: msgBody }), mode: 'no-cors' });
            showToast("Broadcast dispatched.", "success");
            setMsgBody('');
        } catch (e) { showToast("Broadcast failed.", "error"); } finally { setIsSending(false); }
    };

    const handleSaveMaintenance = async () => {
        setIsSavingMaint(true);
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_settings',
                    ...settings,
                    maintenanceMode: maintMode,
                    maintenanceMessage: maintMessage
                }),
                mode: 'no-cors'
            });
            onSettingsUpdate({ maintenanceMode: maintMode, maintenanceMessage: maintMessage });
            showToast(maintMode ? "Maintenance Lock Active" : "Access Restored", "success");
        } catch (e) { showToast("Status update failed.", "error"); } finally { setIsSavingMaint(false); }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fadeIn font-sans px-4 md:px-0">
            {/* Header matches Staff Directory style */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6">
                <div>
                    <h2 className="text-3xl font-normal text-slate-800 uppercase tracking-tight leading-none flex items-center gap-3">
                        System Security
                    </h2>
                    <p className="text-[10px] text-slate-400 font-normal uppercase tracking-[0.25em] mt-2">Security Console & Access Control</p>
                </div>
                <div className="flex items-center gap-3 px-6 py-3 bg-white border border-slate-100 rounded-2xl shadow-sm">
                    <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                    <span className="text-[10px] font-normal text-slate-500 uppercase tracking-widest">Administrator Authenticated</span>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Global Alerts Module */}
                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden flex flex-col">
                    <div className="px-10 py-6 border-b border-slate-50 bg-slate-50/50">
                        <h3 className="text-xs font-normal text-slate-800 uppercase tracking-[0.2em]">Global Alerts</h3>
                    </div>
                    <div className="p-10 space-y-6 flex-1">
                        <div className="space-y-2">
                            <label className="text-[10px] font-normal text-slate-400 uppercase tracking-widest ml-1">Message Body</label>
                            <textarea 
                                className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl h-32 outline-none focus:ring-2 focus:ring-indigo-500/10 font-normal text-sm text-slate-600 transition-all resize-none" 
                                placeholder="Enter system-wide notification..." 
                                value={msgBody} 
                                onChange={e => setMsgBody(e.target.value)}
                            />
                        </div>
                        <div className="flex items-center gap-4">
                            <select 
                                value={msgType} 
                                onChange={(e: any) => setMsgType(e.target.value)}
                                className="px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl text-[10px] font-normal uppercase tracking-widest text-slate-600 outline-none"
                            >
                                <option value="info">Info</option>
                                <option value="warning">Warning</option>
                                <option value="critical">Critical</option>
                            </select>
                            <button onClick={handleBroadcast} disabled={isSending} className="flex-1 py-4 bg-slate-900 hover:bg-black text-white font-normal rounded-xl shadow-xl transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-[0.2em] active:scale-95 disabled:opacity-50">
                                {isSending ? 'Sending...' : 'Dispatch Alert'}
                            </button>
                        </div>
                    </div>
                </div>

                {/* System Access Module */}
                <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden flex flex-col">
                    <div className="px-10 py-6 border-b border-slate-50 bg-slate-50/50">
                        <h3 className="text-xs font-normal text-slate-800 uppercase tracking-[0.2em]">Access Management</h3>
                    </div>
                    <div className="p-10 space-y-8 flex-1">
                        <div className="flex items-center justify-between p-6 bg-slate-50 border border-slate-100 rounded-2xl">
                            <div>
                                <span className="text-sm font-normal text-slate-800 uppercase tracking-tight">Maintenance Mode</span>
                                <p className="text-[10px] text-slate-400 font-normal uppercase tracking-widest mt-1">Restrict all system access</p>
                            </div>
                            <button onClick={() => setMaintMode(!maintMode)} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-all duration-300 ${maintMode ? 'bg-rose-500 shadow-[0_0_10px_rgba(244,63,94,0.3)]' : 'bg-slate-200'}`}>
                                <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform duration-300 ${maintMode ? 'translate-x-6' : 'translate-x-1'}`} />
                            </button>
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-normal text-slate-400 uppercase tracking-widest ml-1">Lockdown Message</label>
                            <input 
                                type="text" 
                                value={maintMessage} 
                                onChange={(e) => setMaintMessage(e.target.value)}
                                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-normal text-slate-700 outline-none text-sm"
                            />
                        </div>
                        <button onClick={handleSaveMaintenance} disabled={isSavingMaint} className="w-full py-4 bg-slate-900 hover:bg-black text-white font-normal rounded-xl shadow-xl transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-[0.2em] active:scale-95 disabled:opacity-50">
                            {isSavingMaint ? 'Syncing...' : 'Update System Status'}
                        </button>
                    </div>
                </div>
            </div>

            {/* License Section */}
            <div className="bg-white rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
                <div className="px-10 py-6 border-b border-slate-50 bg-slate-50/50 flex justify-between items-center">
                    <h3 className="text-xs font-normal text-slate-800 uppercase tracking-[0.2em]">License Status</h3>
                    <span className="text-[10px] font-normal text-slate-400 uppercase tracking-widest">Validity: {subscription?.expiryDate || 'N/A'}</span>
                </div>
                <div className="p-10">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                            <p className="text-[9px] font-normal text-slate-400 uppercase tracking-widest mb-1">Current Tier</p>
                            <p className="text-lg font-normal text-slate-800 uppercase tracking-tight">{subscription?.plan || 'Enterprise'}</p>
                        </div>
                        <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                            <p className="text-[9px] font-normal text-slate-400 uppercase tracking-widest mb-1">Status</p>
                            <span className={`text-[10px] font-normal px-3 py-1 rounded-full uppercase tracking-widest ${subscription?.status === 'Active' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' : 'bg-rose-50 text-rose-600 border border-rose-100'}`}>
                                {subscription?.status || 'Active'}
                            </span>
                        </div>
                        <div className="p-6 bg-slate-50 rounded-2xl border border-slate-100">
                            <p className="text-[9px] font-normal text-slate-400 uppercase tracking-widest mb-1">Days Remaining</p>
                            <p className="text-lg font-normal text-slate-800 uppercase tracking-tight">{subscription?.daysRemaining || 0} Days</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="text-center py-4">
                <p className="text-[9px] font-normal text-slate-300 uppercase tracking-[0.4em]">Proprietary Modular Framework v2.0</p>
            </div>
        </div>
    );
};

