import React, { useState } from 'react';
import { User, SystemSettings, SubscriptionDetails } from '../types';

interface MaintenanceViewProps {
    user: User;
    appScriptUrl: string;
    settings: SystemSettings;
    onSettingsUpdate: (newSettings: Partial<SystemSettings>) => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    onRefreshSubscription?: () => void;
    subscription?: SubscriptionDetails | null;
    history?: any[];
}

const MaintenanceView: React.FC<MaintenanceViewProps> = ({ 
    appScriptUrl, settings, onSettingsUpdate, showToast, subscription 
}) => {
    const [msgType, setMsgType] = useState<'info' | 'warning' | 'critical'>('info');
    const [msgBody, setMsgBody] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [maintMode, setMaintMode] = useState(settings.maintenanceMode || false);
    const [maintMessage, setMaintMessage] = useState(settings.maintenanceMessage || 'System under scheduled maintenance.');
    const [isSavingMaint, setIsSavingMaint] = useState(false);

    const handleBroadcast = async () => {
        if (!msgBody.trim()) { showToast("Enter alert message.", "error"); return; }
        setIsSending(true);
        try {
            await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'broadcast', type: msgType, message: msgBody }), mode: 'no-cors' });
            showToast("Broadcast dispatched.", "success");
            setMsgBody('');
        } catch (e) { showToast("Broadcast failed.", "error"); } finally { setIsSending(false); }
    };

    const handleSaveMaintenance = async () => {
        setIsSavingMaint(true);
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'update_settings',
                    ...settings,
                    maintenanceMode: maintMode,
                    maintenanceMessage: maintMessage
                }),
                mode: 'no-cors'
            });
            onSettingsUpdate({ maintenanceMode: maintMode, maintenanceMessage: maintMessage });
            showToast(maintMode ? "Maintenance Lock Active" : "Access Restored", "success");
        } catch (e) { showToast("Status update failed.", "error"); } finally { setIsSavingMaint(false); }
    };

    return (
        <div className="max-w-6xl mx-auto space-y-4 sm:space-y-6 animate-fadeIn font-sans px-2 md:px-0">
            {/* Header matches Staff Directory style exactly */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 px-2">
                <div>
                    <h2 className="text-2xl sm:text-3xl font-normal text-slate-800 uppercase tracking-tight leading-none">
                        System Security
                    </h2>
                    <p className="text-[9px] text-slate-400 font-normal uppercase tracking-[0.25em] mt-2">Access Control & Management Console</p>
                </div>
                <div className="hidden sm:flex items-center gap-3 px-5 py-2.5 bg-white border border-slate-100 rounded-2xl shadow-sm">
                    <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                    <span className="text-[9px] font-normal text-slate-500 uppercase tracking-widest">Admin Mode</span>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 sm:gap-6">
                {/* Global Alerts Module */}
                <div className="bg-white rounded-[1.5rem] sm:rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden flex flex-col">
                    <div className="px-6 py-4 sm:px-8 sm:py-5 border-b border-slate-50 bg-slate-50/50">
                        <h3 className="text-[10px] font-normal text-slate-800 uppercase tracking-[0.2em]">Global Alerts</h3>
                    </div>
                    <div className="p-6 sm:p-8 space-y-4 flex-1">
                        <textarea 
                            className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl h-24 sm:h-28 outline-none focus:ring-2 focus:ring-indigo-500/10 font-normal text-xs text-slate-600 transition-all resize-none" 
                            placeholder="System-wide notification text..." 
                            value={msgBody} 
                            onChange={e => setMsgBody(e.target.value)}
                        />
                        <div className="flex items-center gap-3">
                            <select 
                                value={msgType} 
                                onChange={(e: any) => setMsgType(e.target.value)}
                                className="px-3 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-[10px] font-normal uppercase tracking-widest text-slate-600 outline-none"
                            >
                                <option value="info">Info</option>
                                <option value="warning">Warning</option>
                                <option value="critical">Critical</option>
                            </select>
                            <button onClick={handleBroadcast} disabled={isSending} className="flex-1 py-3 bg-slate-900 hover:bg-black text-white font-normal rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 text-[10px] uppercase tracking-[0.2em] active:scale-95 disabled:opacity-50">
                                {isSending ? 'Sending...' : 'Dispatch Alert'}
                            </button>
                        </div>
                    </div>
                </div>

                {/* System Access Module */}
                <div className="bg-white rounded-[1.5rem] sm:rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden flex flex-col">
                    <div className="px-6 py-4 sm:px-8 sm:py-5 border-b border-slate-50 bg-slate-50/50">
                        <h3 className="text-[10px] font-normal text-slate-800 uppercase tracking-[0.2em]">Access Management</h3>
                    </div>
                    <div className="p-6 sm:p-8 space-y-4 flex-1">
                        <div className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-xl">
                            <div>
                                <span className="text-xs font-normal text-slate-800 uppercase tracking-tight">Maintenance Mode</span>
                                <p className="text-[8px] text-slate-400 font-normal uppercase tracking-widest mt-0.5">Restrict system access</p>
                            </div>
                            <button onClick={() => setMaintMode(!maintMode)} className={`relative inline-flex h-5 w-10 items-center rounded-full transition-all duration-300 ${maintMode ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.3)]' : 'bg-slate-200'}`}>
                                <span className={`inline-block h-3.5 w-3.5 transform rounded-full bg-white transition-transform duration-300 ${maintMode ? 'translate-x-6' : 'translate-x-0.5'}`} />
                            </button>
                        </div>
                        <input 
                            type="text" 
                            value={maintMessage} 
                            onChange={(e) => setMaintMessage(e.target.value)}
                            placeholder="Maintenance display message"
                            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-normal text-slate-700 outline-none text-xs"
                        />
                        <button onClick={handleSaveMaintenance} disabled={isSavingMaint} className="w-full py-3 bg-slate-900 hover:bg-black text-white font-normal rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 text-[10px] uppercase tracking-[0.2em] active:scale-95 disabled:opacity-50">
                            {isSavingMaint ? 'Syncing...' : 'Update Status'}
                        </button>
                    </div>
                </div>
            </div>

            {/* License Section */}
            <div className="bg-white rounded-[1.5rem] sm:rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden">
                <div className="px-6 py-4 sm:px-8 sm:py-5 border-b border-slate-50 bg-slate-50/50 flex justify-between items-center">
                    <h3 className="text-[10px] font-normal text-slate-800 uppercase tracking-[0.2em]">License Status</h3>
                    <span className="text-[9px] font-normal text-slate-400 uppercase tracking-widest">Valid Thru: {subscription?.expiryDate || 'N/A'}</span>
                </div>
