import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const SectionHeader = ({ label }: { label: string }) => (
    <div className="w-full flex items-center gap-4 sm:gap-6 mb-4 sm:mb-6 opacity-80 shrink-0">
        <span className="text-[10px] sm:text-[11px] font-black text-slate-300 uppercase tracking-[0.4em] whitespace-nowrap">{label}</span>
        <div className="h-px flex-1 bg-gradient-to-r from-slate-100 to-transparent"></div>
    </div>
);

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    const [formData, setFormData] = useState({
        name: '', username: '', password: '', role: 'Inspector' as any, position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const isSuperAdmin = currentUser.role === 'SuperAdmin';
    const isAdmin = currentUser.role === 'Admin' || isSuperAdmin;

    useEffect(() => { 
        if (isAdmin) fetchUsers(); 
    }, [isAdmin]);

    if (!isAdmin) {
        return (
            <div className="flex flex-col items-center justify-center py-20 text-center font-sans min-h-[60vh]">
                <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                </div>
                <h3 className="text-xl font-black text-slate-800 tracking-tight uppercase">Access Restricted</h3>
                <p className="text-slate-500 max-w-xs mt-2 text-xs font-bold uppercase tracking-widest leading-relaxed">Administrator level clearance required for personnel management.</p>
            </div>
        );
    }

    const fetchUsers = async (force: boolean = false) => {
        if (!appScriptUrl) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) });
            const result = await response.json();
            if (result.status === 'success' && Array.isArray(result.users)) {
                setUsers(result.users);
            }
        } catch (e) { showToast("Failed to load users", 'error'); } finally { setIsLoading(false); }
    };

    const handleDelete = async (username: string) => {
        if (!window.confirm(`Remove user "${username}"?`)) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'delete_user', username }) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast("User removed successfully", 'success');
                fetchUsers();
            } else { showToast(result.message || "Delete failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsLoading(false); }
    };

    const handleToggleStatus = async (user: User) => {
        if (user.username === currentUser.username) {
            showToast("You cannot restrict your own access.", "warning");
            return;
        }
        if (user.role === 'SuperAdmin') {
            showToast("SuperAdmin access cannot be restricted.", "error");
            return;
        }

        const nextStatus = !user.isActive;
        setUsers(prev => prev.map(u => u.username === user.username ? { ...u, isActive: nextStatus } : u));

        try {
            const response = await fetch(appScriptUrl, { 
                method: 'POST', 
                body: JSON.stringify({ 
                    action: 'update_user', 
                    username: user.username,
                    isActive: nextStatus
                }) 
            });
            const result = await response.json();
            if (result.status !== 'success') {
                setUsers(prev => prev.map(u => u.username === user.username ? { ...u, isActive: !nextStatus } : u));
                showToast("Failed to sync access state.", "error");
            } else {
                showToast(`Access ${nextStatus ? 'restored' : 'restricted'} for ${user.name || user.username}`, "info");
            }
        } catch (e) {
            setUsers(prev => prev.map(u => u.username === user.username ? { ...u, isActive: !nextStatus } : u));
            showToast("Connection failed.", "error");
        }
    };

    const handleEdit = (user: User) => {
        setFormData({ name: user.name || '', username: user.username, role: user.role as any, position: user.position || '', password: '' });
        setOriginalUsername(user.username);
        setIsEditing(true);
        setViewMode('form');
    };

    const handleShare = async (u: User) => {
        const orgName = settings?.companyName || 'Fleet Operations';
        const msg = `*${orgName.toUpperCase()} - STAFF IDENTITY*\n\n*Name:* ${u.name || 'Setup Pending'}\n*Role:* ${u.role}\n*Job Title:* ${u.position || 'N/A'}\n*Login Email:* ${u.username}\n\n_Security Notice: Identity verified in Fleet Portal._`;

        if (navigator.share) {
            try { await navigator.share({ title: 'Staff Identity Detail', text: msg }); } catch (e) { if (e instanceof Error && e.name !== 'AbortError') fallbackCopy(msg); }
        } else { fallbackCopy(msg); }
    };

    const fallbackCopy = (text: string) => {
        navigator.clipboard.writeText(text).then(() => showToast("Professional details copied to clipboard", "success")).catch(() => showToast("Failed to share details", "error"));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.username) { showToast("Login Email is required.", 'error'); return; }

        setIsSubmitting(true);
        try {
            const payload: any = { action: isEditing ? 'update_user' : 'register_user', ...formData, preferences: { ... (isEditing ? {} : { mustChangePassword: true }) } };
            if (isEditing) payload.originalUsername = originalUsername;
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast(isEditing ? "Staff details updated" : "Invite sent to new staff member", 'success');
                setViewMode('list');
                fetchUsers();
            } else { showToast(result.message || "Operation failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsSubmitting(false); }
    };

    if (viewMode === 'form') {
        return (
            <div className="max-w-2xl mx-auto py-2 sm:py-6 flex flex-col items-center justify-center min-h-[calc(100vh-140px)] px-2 sm:px-4 animate-fadeIn font-sans overflow-hidden">
                <div className="w-full space-y-6 sm:space-y-8">
                    <button onClick={() => setViewMode('list')} className="mb-4 text-[10px] font-black text-slate-400 hover:text-slate-800 flex items-center gap-2 transition-colors group uppercase tracking-[0.2em]">
                        <svg className="w-4 h-4 group-hover:-translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                        Exit Configuration
                    </button>

                    <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden p-6 sm:p-10">
                        <SectionHeader label={isEditing ? "Profile Synthesis" : "New Enrollment"} />

                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-4">
                                    <div>
                                        <label className="block text-[9px] font-black uppercase text-slate-400 mb-2 tracking-[0.2em]">Login ID (Email) *</label>
                                        <input type="email" required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500/20 outline-none transition font-bold text-slate-700 text-sm" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} placeholder="staff@domain.com" />
                                    </div>
                                    <div>
                                        <label className="block text-[9px] font-black uppercase text-slate-400 mb-2 tracking-[0.2em]">System Clearance</label>
                                        <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold text-slate-700 outline-none h-[58px] appearance-none" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as any})}>
                                            <option value="Inspector">Inspector</option>
                                            <option value="Operations">Operations</option>
                                            <option value="Maintenance">Maintenance</option>
                                            <option value="Admin">Admin</option>
                                            {isSuperAdmin && <option value="SuperAdmin">SuperAdmin</option>}
                                        </select>
                                    </div>
                                </div>
                                <div className="space-y-4">
                                    <AutocompleteInput label="Official Job Title" value={formData.position} onChange={v => setFormData({...formData, position: v})} options={validationLists.positions} isTitleCase={true} placeholder="Designation" />
                                    {isEditing && (
                                        <AutocompleteInput label="Full Identity Name" value={formData.name} onChange={v => setFormData({...formData, name: v})} options={validationLists.inspectors} isTitleCase={true} />
                                    )}
                                    {!isEditing && (
                                        <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl flex items-start gap-3 mt-4 sm:mt-0">
                                            <svg className="w-5 h-5 text-indigo-500 shrink-0 mt-0.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                                            <p className="text-[9px] text-indigo-700 font-bold leading-relaxed uppercase tracking-wider">
                                                Enrolling users must establish unique credentials upon initial portal entry.
                                            </p>
                                        </div>
                                    )}
                                </div>
                            </div>

                            <div className="pt-6 border-t border-slate-50 flex justify-end">
                                <button type="submit" disabled={isSubmitting} className="w-full md:w-auto px-12 py-4 bg-slate-900 hover:bg-black text-white font-black rounded-2xl shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 uppercase tracking-[0.3em] text-[10px]">
                                    {isSubmitting ? <svg className="animate-spin h-4 w-4 text-indigo-400" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> : null}
                                    {isSubmitting ? 'Syncing...' : isEditing ? 'Update Profile' : 'Authorize Identity'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto py-2 sm:py-6 flex flex-col min-h-[calc(100vh-140px)] px-2 sm:px-4 animate-fadeIn font-sans overflow-hidden">
            <div className="w-full max-w-5xl space-y-6 sm:space-y-10 flex-1">

                {/* Standardized Header */}
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 px-2">
                    <div>
