                                className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-mono text-[9px] text-slate-500 h-24 outline-none focus:ring-4 focus:ring-indigo-500/5 disabled:opacity-50 resize-none" 
                                placeholder="Encoded image payload..."
                            />
                        </div>

                        {isAdmin && (
                            <div className="flex justify-end pt-6 border-t border-slate-50">
                                <button 
                                    onClick={handleSaveSettings} 
                                    disabled={isSavingSettings} 
                                    className="w-full sm:w-auto px-12 py-4 bg-slate-900 hover:bg-black text-white rounded-2xl font-black shadow-xl flex items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-[0.2em] text-[10px]"
                                >
