import React, { useState, useRef } from 'react';
import { ValidationLists } from '../types';

interface FleetRegistryViewProps {
    appScriptUrl: string;
    validationLists: ValidationLists;
    onRefresh: () => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    isLocked?: boolean;
}

const SectionHeader = ({ label }: { label: string }) => (
    <div className="w-full flex items-center gap-4 sm:gap-6 mb-4 sm:mb-8 opacity-80 shrink-0">
        <span className="text-[10px] sm:text-[11px] font-black text-slate-300 uppercase tracking-[0.4em] whitespace-nowrap">{label}</span>
        <div className="h-px flex-1 bg-gradient-to-r from-slate-100 to-transparent"></div>
    </div>
);

const FleetRegistryView: React.FC<FleetRegistryViewProps> = ({ 
    appScriptUrl, validationLists, onRefresh, showToast, isLocked 
}) => {
    const [newTruck, setNewTruck] = useState('');
    const [newTrailer, setNewTrailer] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isImporting, setIsImporting] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAddAsset = async (type: 'truck' | 'trailer') => {
        const val = type === 'truck' ? newTruck : newTrailer;
        if (!val.trim() || isLocked) return;
        setIsSubmitting(true);
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'manage_fleet', type, value: val.trim().toUpperCase() }),
                mode: 'no-cors'
            });
            showToast(`${type === 'truck' ? 'Truck' : 'Trailer'} registered`, "success");
            if (type === 'truck') setNewTruck(''); else setNewTrailer('');
            setTimeout(onRefresh, 1000);
        } finally { setIsSubmitting(false); }
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || isLocked) return;
        const reader = new FileReader();
        reader.onload = async (event) => {
            const content = event.target?.result as string;
            if (!content) return;
            setIsImporting(true);
            try {
                const lines = content.split(/\r?\n/);
                const trucks: string[] = [];
                const trailers: string[] = [];
                for (let i = 1; i < lines.length; i++) {
                    const line = lines[i].trim();
                    if (!line) continue;
                    const [truck, trailer] = line.split(',').map(s => s?.trim().toUpperCase() || "");
                    if (truck) trucks.push(truck);
                    if (trailer) trailers.push(trailer);
                }
                if (trucks.length === 0 && trailers.length === 0) {
                    showToast("No data identified", "warning");
                    return;
                }
                await fetch(appScriptUrl, {
                    method: 'POST',
                    body: JSON.stringify({ action: 'bulk_manage_fleet', trucks, trailers }),
                    mode: 'no-cors'
                });
                showToast("Import complete", "success");
                setTimeout(onRefresh, 1500);
            } finally { 
                setIsImporting(false); 
                if (fileInputRef.current) fileInputRef.current.value = ""; 
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="max-w-6xl mx-auto py-2 sm:py-6 flex flex-col min-h-[calc(100vh-140px)] px-2 sm:px-4 animate-fadeIn font-sans overflow-hidden">
            <div className="w-full max-w-5xl space-y-6 sm:space-y-10 flex-1 flex flex-col">

                {/* Standardized Header matching main menu */}
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 px-2">
                    <div>
                        <h2 className="text-3xl font-normal text-slate-800 uppercase tracking-tight leading-none">
                            Fleet Registry
                        </h2>
                        <p className="text-[9px] text-slate-400 font-normal uppercase tracking-[0.25em] mt-2">Validated Asset Inventory</p>
                    </div>
                    <div className="flex gap-2 w-full sm:w-auto">
                        <input type="file" accept=".csv" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            disabled={isLocked || isImporting}
                            className="flex-1 sm:flex-none px-6 py-3 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95 disabled:opacity-30 flex items-center justify-center gap-2 shadow-lg"
                        >
                            {isImporting ? 'Processing...' : 'Bulk Import CSV'}
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 flex-1">
                    {/* Trucks Section */}
                    <div className="flex flex-col">
                        <SectionHeader label="Unit Master List" />
                        <div className="flex gap-2 mb-4">
                            <input type="text" placeholder="New Horse Reg..." className="flex-1 p-3 bg-white border border-slate-100 rounded-xl text-xs font-bold uppercase outline-none focus:ring-4 focus:ring-indigo-50 transition-all shadow-sm" value={newTruck} onChange={e => setNewTruck(e.target.value)} />
                            <button onClick={() => handleAddAsset('truck')} disabled={isSubmitting || !newTruck.trim() || isLocked} className="px-5 py-3 bg-indigo-600 text-white rounded-xl font-bold text-[9px] uppercase tracking-[0.2em] active:scale-95 shadow-lg shadow-indigo-100 disabled:opacity-30">Add</button>
                        </div>
                        <div className="bg-white rounded-[1.5rem] sm:rounded-[2rem] border border-slate-50 overflow-hidden flex-1 flex flex-col shadow-sm">
                            <div className="p-4 bg-slate-50/50 border-b border-slate-50 flex justify-between items-center">
                                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Active Units</span>
                                <span className="text-[9px] font-black bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded-full">{validationLists.trucks.length}</span>
                            </div>
                            <div className="flex-1 overflow-y-auto divide-y divide-slate-50 max-h-[30vh] sm:max-h-none scrollbar-hide">
                                {validationLists.trucks.map((t, i) => (
                                    <div key={i} className="px-6 py-3.5 text-[11px] font-black text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors uppercase tracking-tight">{t}</div>
                                ))}
                            </div>
                        </div>
                    </div>

                    {/* Trailers Section */}
                    <div className="flex flex-col">
                        <SectionHeader label="Trailer Inventory" />
                        <div className="flex gap-2 mb-4">
                            <input type="text" placeholder="New Trailer ID..." className="flex-1 p-3 bg-white border border-slate-100 rounded-xl text-xs font-bold uppercase outline-none focus:ring-4 focus:ring-emerald-50 transition-all shadow-sm" value={newTrailer} onChange={e => setNewTrailer(e.target.value)} />
                            <button onClick={() => handleAddAsset('trailer')} disabled={isSubmitting || !newTrailer.trim() || isLocked} className="px-5 py-3 bg-emerald-600 text-white rounded-xl font-bold text-[9px] uppercase tracking-[0.2em] active:scale-95 shadow-lg shadow-emerald-100 disabled:opacity-30">Add</button>
                        </div>
                        <div className="bg-white rounded-[1.5rem] sm:rounded-[2rem] border border-slate-50 overflow-hidden flex-1 flex flex-col shadow-sm">
                            <div className="p-4 bg-slate-50/50 border-b border-slate-50 flex justify-between items-center">
                                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Active Trailers</span>
                                <span className="text-[9px] font-black bg-emerald-50 text-emerald-600 px-2 py-0.5 rounded-full">{validationLists.trailers.length}</span>
                            </div>
                            <div className="flex-1 overflow-y-auto divide-y divide-slate-50 max-h-[30vh] sm:max-h-none scrollbar-hide">
                                {validationLists.trailers.map((t, i) => (
                                    <div key={i} className="px-6 py-3.5 text-[11px] font-black text-slate-600 hover:bg-slate-50 hover:text-slate-900 transition-colors uppercase tracking-tight">{t}</div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

