    );
};

export default UserManagementView;

import React, { useState, useEffect } from 'react';
import { User, ValidationLists, SystemSettings } from '../types';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface UserManagementViewProps {
    currentUser: User;
    appScriptUrl: string;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    validationLists: ValidationLists;
    settings?: SystemSettings;
}

const SectionHeader = ({ label }: { label: string }) => (
    <div className="w-full flex items-center gap-4 sm:gap-6 mb-4 sm:mb-6 opacity-80 shrink-0">
        <span className="text-[10px] sm:text-[11px] font-black text-slate-300 uppercase tracking-[0.4em] whitespace-nowrap">{label}</span>
        <div className="h-px flex-1 bg-gradient-to-r from-slate-100 to-transparent"></div>
    </div>
);

const UserManagementView: React.FC<UserManagementViewProps> = ({ currentUser, appScriptUrl, showToast, validationLists, settings }) => {
    const [users, setUsers] = useState<(User & {password?: string})[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
    const [isEditing, setIsEditing] = useState(false);
    const [originalUsername, setOriginalUsername] = useState('');

    const [formData, setFormData] = useState({
        name: '', username: '', password: '', role: 'Inspector' as any, position: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);

    const isSuperAdmin = currentUser.role === 'SuperAdmin';
    const isAdmin = currentUser.role === 'Admin' || isSuperAdmin;

    useEffect(() => { 
        if (isAdmin) fetchUsers(); 
    }, [isAdmin]);

    if (!isAdmin) {
        return (
            <div className="flex flex-col items-center justify-center py-20 text-center font-sans min-h-[60vh]">
                <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mb-4">
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
                </div>
                <h3 className="text-xl font-normal text-slate-800 tracking-tight uppercase">Access Restricted</h3>
                <p className="text-slate-500 max-w-xs mt-2 text-[10px] font-medium uppercase tracking-widest leading-relaxed">Personnel registry requires administrative clearance.</p>
            </div>
        );
    }

    const fetchUsers = async (force: boolean = false) => {
        if (!appScriptUrl) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'get_users' }) });
            const result = await response.json();
            if (result.status === 'success' && Array.isArray(result.users)) {
                setUsers(result.users);
            }
        } catch (e) { showToast("Failed to load users", 'error'); } finally { setIsLoading(false); }
    };

    const handleDelete = async (username: string) => {
        if (!window.confirm(`Remove user "${username}"?`)) return;
        setIsLoading(true);
        try {
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify({ action: 'delete_user', username }) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast("User removed successfully", 'success');
                fetchUsers();
            } else { showToast(result.message || "Delete failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsLoading(false); }
    };

    const handleToggleStatus = async (user: User) => {
        if (user.username === currentUser.username) {
            showToast("You cannot restrict your own access.", "warning");
            return;
        }
        if (user.role === 'SuperAdmin') {
            showToast("SuperAdmin access cannot be restricted.", "error");
            return;
        }

        const nextStatus = !user.isActive;
        setUsers(prev => prev.map(u => u.username === user.username ? { ...u, isActive: nextStatus } : u));

        try {
            const response = await fetch(appScriptUrl, { 
                method: 'POST', 
                body: JSON.stringify({ 
                    action: 'update_user', 
                    username: user.username,
                    isActive: nextStatus
                }) 
            });
            const result = await response.json();
            if (result.status !== 'success') {
                setUsers(prev => prev.map(u => u.username === user.username ? { ...u, isActive: !nextStatus } : u));
                showToast("Failed to sync access state.", "error");
            } else {
                showToast(`Access ${nextStatus ? 'restored' : 'restricted'} for ${user.name || user.username}`, "info");
            }
        } catch (e) {
            setUsers(prev => prev.map(u => u.username === user.username ? { ...u, isActive: !nextStatus } : u));
            showToast("Connection failed.", "error");
        }
    };

    const handleEdit = (user: User) => {
        setFormData({ name: user.name || '', username: user.username, role: user.role as any, position: user.position || '', password: '' });
        setOriginalUsername(user.username);
        setIsEditing(true);
        setViewMode('form');
    };

    const handleShare = async (u: User) => {
        const orgName = settings?.companyName || 'Fleet Operations';
        const msg = `*${orgName.toUpperCase()} - STAFF IDENTITY*\n\n*Name:* ${u.name || 'Setup Pending'}\n*Role:* ${u.role}\n*Job Title:* ${u.position || 'N/A'}\n*Login Email:* ${u.username}\n\n_Security Notice: Identity verified in Fleet Portal._`;

        if (navigator.share) {
            try { await navigator.share({ title: 'Staff Identity Detail', text: msg }); } catch (e) { if (e instanceof Error && e.name !== 'AbortError') fallbackCopy(msg); }
        } else { fallbackCopy(msg); }
    };

    const fallbackCopy = (text: string) => {
        navigator.clipboard.writeText(text).then(() => showToast("Details copied", "success")).catch(() => showToast("Failed to share", "error"));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.username) { showToast("Login Email is required.", 'error'); return; }

        setIsSubmitting(true);
        try {
            const payload: any = { action: isEditing ? 'update_user' : 'register_user', ...formData, preferences: { ... (isEditing ? {} : { mustChangePassword: true }) } };
            if (isEditing) payload.originalUsername = originalUsername;
            const response = await fetch(appScriptUrl, { method: 'POST', body: JSON.stringify(payload) });
            const result = await response.json();
            if (result.status === 'success') {
                showToast(isEditing ? "Staff details updated" : "Enrollment invite sent", 'success');
                setViewMode('list');
                fetchUsers();
            } else { showToast(result.message || "Operation failed", 'error'); }
        } catch (e) { showToast("Connection failed", 'error'); } finally { setIsSubmitting(false); }
    };

    if (viewMode === 'form') {
        return (
            <div className="max-w-2xl mx-auto py-2 sm:py-6 flex flex-col items-center justify-center min-h-[calc(100vh-140px)] px-2 sm:px-4 animate-fadeIn font-sans overflow-hidden">
                <div className="w-full space-y-4">
                    <button onClick={() => setViewMode('list')} className="text-[10px] font-medium text-slate-400 hover:text-slate-800 flex items-center gap-2 transition-colors uppercase tracking-[0.2em]">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7"></path></svg>
                        Back
                    </button>

                    <div className="bg-white rounded-[1.5rem] sm:rounded-[2rem] shadow-sm border border-slate-100 p-6 sm:p-10">
                        <SectionHeader label={isEditing ? "Configure Profile" : "Personnel Onboarding"} />
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div className="space-y-4">
                                    <div>
                                        <label className="block text-[9px] font-bold uppercase text-slate-400 mb-2 tracking-[0.2em]">Login ID (Email) *</label>
                                        <input type="email" required className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none transition font-medium text-slate-700 text-sm" value={formData.username} onChange={e => setFormData({...formData, username: e.target.value})} placeholder="staff@domain.com" />
                                    </div>
                                    <div>
                                        <label className="block text-[9px] font-bold uppercase text-slate-400 mb-2 tracking-[0.2em]">Clearance Level</label>
                                        <select className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-medium text-slate-700 outline-none h-[52px] appearance-none" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value as any})}>
                                            <option value="Inspector">Inspector</option>
                                            <option value="Operations">Operations</option>
                                            <option value="Maintenance">Maintenance</option>
                                            <option value="Admin">Admin</option>
                                            {isSuperAdmin && <option value="SuperAdmin">SuperAdmin</option>}
                                        </select>
                                    </div>
                                </div>
                                <div className="space-y-4">
                                    <AutocompleteInput label="Official Job Title" value={formData.position} onChange={v => setFormData({...formData, position: v})} options={validationLists.positions} isTitleCase={true} placeholder="Designation" />
                                    {isEditing && (
                                        <AutocompleteInput label="Full Identity Name" value={formData.name} onChange={v => setFormData({...formData, name: v})} options={validationLists.inspectors} isTitleCase={true} />
                                    )}
                                </div>
                            </div>
                            <div className="pt-4 flex justify-end">
                                <button type="submit" disabled={isSubmitting} className="w-full md:w-auto px-10 py-3.5 bg-slate-900 hover:bg-black text-white font-medium rounded-2xl transition-all active:scale-95 flex items-center justify-center gap-3 uppercase tracking-[0.2em] text-[10px]">
                                    {isSubmitting ? 'Processing...' : isEditing ? 'Sync Profile' : 'Complete Enrollment'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto py-2 sm:py-6 flex flex-col min-h-[calc(100vh-140px)] px-2 sm:px-4 animate-fadeIn font-sans overflow-hidden">
            <div className="w-full space-y-6 flex-1 flex flex-col min-h-0">

                {/* Unified Header matching Main Menu */}
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 px-2 shrink-0">
                    <div>
                        <h2 className="text-3xl font-normal text-slate-800 uppercase tracking-tight leading-none">
                            Staff Directory
                        </h2>
                        <p className="text-[9px] text-slate-400 font-normal uppercase tracking-[0.25em] mt-2">Personnel Management</p>
                    </div>
                    <button onClick={() => { setFormData({ name: '', username: '', password: '', role: 'Inspector', position: '' }); setIsEditing(false); setViewMode('form'); }} className="w-full sm:w-auto px-8 py-3.5 bg-slate-900 hover:bg-black text-white font-medium rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 group text-[10px] uppercase tracking-[0.3em] active:scale-95">
                        <svg className="w-4 h-4 transition-transform group-hover:rotate-90" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 4v16m8-8H4"></path></svg>
                        New Enrollment
                    </button>
                </div>

                <div className="flex flex-col flex-1 min-h-0">
                    <SectionHeader label="Fleet Personnel Inventory" />

                    <div className="bg-white rounded-[1.5rem] sm:rounded-[2rem] shadow-sm border border-slate-100 overflow-hidden flex-1 flex flex-col min-h-0">
                        <div className="flex-1 overflow-y-auto scrollbar-hide">
                            <table className="w-full text-left text-sm border-collapse block md:table">
                                <thead className="bg-slate-50/50 text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] border-b border-slate-50 hidden md:table-header-group sticky top-0 z-10 backdrop-blur-md">
                                    <tr className="md:table-row">
                                        <th className="px-8 py-5 md:table-cell">Identity</th>
                                        <th className="px-8 py-5 md:table-cell">Clearance</th>
                                        <th className="px-8 py-5 md:table-cell">Access</th>
                                        <th className="px-8 py-5 text-right md:table-cell">Control</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-50 block md:table-row-group">
                                    {isLoading ? (
                                        <tr className="block md:table-row"><td colSpan={4} className="py-24 text-center"><div className="w-8 h-8 border-2 border-slate-100 border-t-indigo-500 rounded-full animate-spin mx-auto"></div></td></tr>
                                    ) : users.length === 0 ? (
                                        <tr className="block md:table-row"><td colSpan={4} className="py-24 text-center text-[10px] font-medium text-slate-300 uppercase tracking-widest">Registry is empty</td></tr>
                                    ) : users.map((u, i) => {
                                        const isUserSuperAdmin = u.role === 'SuperAdmin';
                                        const hideDetails = isUserSuperAdmin && !isSuperAdmin;

                                        return (
                                            <tr key={i} className={`hover:bg-slate-50/30 transition-colors group block md:table-row relative p-5 md:p-0 ${!u.isActive && 'opacity-60 grayscale-[0.5]'}`}>
                                                <td className="md:px-8 md:py-4 block md:table-cell mb-3 md:mb-0">
                                                    <div className="flex items-center gap-4">
                                                        <div className="w-9 h-9 rounded-xl bg-slate-50 border border-slate-100 flex items-center justify-center font-bold text-slate-300 text-xs shrink-0">
                                                            {u.name ? u.name.substring(0, 2).toUpperCase() : '??'}
                                                        </div>
                                                        <div className="min-w-0">
                                                            <div className="font-bold text-slate-800 text-xs leading-tight truncate uppercase tracking-tight">
                                                                {u.name || 'Setup Pending'}
                                                            </div>
                                                            <div className="text-[10px] text-slate-400 font-normal truncate mt-0.5">
                                                                {hideDetails ? '••••••••' : u.username}
                                                            </div>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="md:px-8 md:py-4 block md:table-cell mb-3 md:mb-0">
                                                    <div className="md:hidden text-[8px] font-bold text-slate-300 uppercase tracking-[0.2em] mb-1.5">Role Type</div>
                                                    <span className={`px-2.5 py-1 rounded-lg text-[9px] font-bold uppercase tracking-widest border
                                                        ${u.role === 'Admin' || isUserSuperAdmin ? 'bg-indigo-50 text-indigo-600 border-indigo-100' : 'bg-slate-50 text-slate-500 border-slate-100'}
                                                    `}>
                                                        {u.role}
                                                    </span>
                                                </td>
                                                <td className="md:px-8 md:py-4 block md:table-cell mb-4 md:mb-0">
                                                    <div className="md:hidden text-[8px] font-bold text-slate-300 uppercase tracking-[0.2em] mb-1.5">System State</div>
                                                    <div className="flex items-center gap-3">
                                                        <button 
                                                            onClick={() => !hideDetails && handleToggleStatus(u)}
                                                            disabled={hideDetails}
                                                            className={`relative inline-flex h-4 w-9 items-center rounded-full transition-all ${hideDetails ? 'opacity-20' : ''} ${u.isActive ? 'bg-emerald-500' : 'bg-slate-200'}`}
                                                        >
                                                            <span className={`inline-block h-3 w-3 transform rounded-full bg-white transition-transform ${u.isActive ? 'translate-x-5' : 'translate-x-1'}`} />
                                                        </button>
                                                        <span className={`text-[9px] font-bold uppercase tracking-widest ${u.isActive ? 'text-emerald-600' : 'text-slate-400'}`}>
                                                            {u.isActive ? 'Active' : 'Locked'}
                                                        </span>
                                                    </div>
                                                </td>
                                                <td className="md:px-8 md:py-4 md:text-right block md:table-cell">
                                                    <div className="flex justify-start md:justify-end gap-1.5 border-t md:border-0 pt-4 md:pt-0 mt-2 md:mt-0">
                                                        {hideDetails ? (
                                                            <span className="text-[9px] font-medium text-slate-300 uppercase tracking-widest px-2 py-1">Classified</span>
                                                        ) : (
                                                            <>
                                                                <button onClick={() => handleShare(u)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all" title="Export">
                                                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"></path></svg>
                                                                </button>
                                                                <button onClick={() => handleEdit(u)} className="p-2 text-blue-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all" title="Configure">
                                                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                                                                </button>
                                                                <button onClick={() => handleDelete(u.username)} className="p-2 text-rose-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl transition-all" title="Purge">
                                                                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                                                                </button>
                                                            </>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

