import React, { useState, useRef } from 'react';
import { ValidationLists } from '../types';

interface FleetRegistryViewProps {
    appScriptUrl: string;
    validationLists: ValidationLists;
    onRefresh: () => void;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    isLocked?: boolean;
}

const SectionHeader = ({ label }: { label: string }) => (
    <div className="w-full flex items-center gap-4 mb-4 sm:mb-6 opacity-70 shrink-0">
        <span className="text-[10px] font-semibold text-slate-400 uppercase tracking-[0.3em] whitespace-nowrap">{label}</span>
        <div className="h-px flex-1 bg-gradient-to-r from-slate-100 to-transparent"></div>
    </div>
);

const FleetRegistryView: React.FC<FleetRegistryViewProps> = ({ 
    appScriptUrl, validationLists, onRefresh, showToast, isLocked 
}) => {
    const [newTruck, setNewTruck] = useState('');
    const [newTrailer, setNewTrailer] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isImporting, setIsImporting] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAddAsset = async (type: 'truck' | 'trailer') => {
        const val = type === 'truck' ? newTruck : newTrailer;
        if (!val.trim() || isLocked) return;
        setIsSubmitting(true);
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'manage_fleet', type, value: val.trim().toUpperCase() }),
                mode: 'no-cors'
            });
            showToast(`${type === 'truck' ? 'Truck' : 'Trailer'} registered`, "success");
            if (type === 'truck') setNewTruck(''); else setNewTrailer('');
            setTimeout(onRefresh, 1000);
        } finally { setIsSubmitting(false); }
    };

    const downloadSampleCsv = () => {
        const csvContent = "Truck,Trailer\nABC 123,T-100\nXYZ 789,T-200";
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", "fleet_registry_sample.csv");
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || isLocked) return;
        const reader = new FileReader();
        reader.onload = async (event) => {
            const content = event.target?.result as string;
            if (!content) return;
            setIsImporting(true);
            try {
                const lines = content.split(/\r?\n/);
                const trucks: string[] = [];
                const trailers: string[] = [];
                for (let i = 1; i < lines.length; i++) {
                    const line = lines[i].trim();
                    if (!line) continue;
                    const [truck, trailer] = line.split(',').map(s => s?.trim().toUpperCase() || "");
                    if (truck) trucks.push(truck);
                    if (trailer) trailers.push(trailer);
                }
                if (trucks.length === 0 && trailers.length === 0) {
                    showToast("No data found", "warning");
                    return;
                }
                await fetch(appScriptUrl, {
                    method: 'POST',
                    body: JSON.stringify({ action: 'bulk_manage_fleet', trucks, trailers }),
                    mode: 'no-cors'
                });
                showToast("Bulk import synchronized", "success");
                setTimeout(onRefresh, 1500);
            } finally { 
                setIsImporting(false); 
                if (fileInputRef.current) fileInputRef.current.value = ""; 
            }
        };
        reader.readAsText(file);
    };

    return (
        <div className="max-w-6xl mx-auto flex flex-col h-[calc(100vh-140px)] py-2 sm:py-4 px-2 sm:px-4 animate-fadeIn font-sans overflow-hidden">
            {/* PINNED HEADER SECTION */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 px-2 mb-6 shrink-0">
                <div>
                    <h2 className="text-3xl font-normal text-slate-800 uppercase tracking-tight leading-none">Fleet Registry</h2>
                    <p className="text-[9px] text-slate-400 font-medium uppercase tracking-[0.3em] mt-2">Asset Inventory Management</p>
                </div>
                <div className="flex flex-col sm:items-end gap-2 w-full sm:w-auto">
                    <div className="flex gap-2 w-full sm:w-auto">
                        <button 
                            onClick={downloadSampleCsv}
                            className="flex-1 sm:flex-none px-5 py-3 bg-white border border-slate-200 text-slate-500 rounded-xl font-semibold text-[10px] uppercase tracking-widest transition-all hover:bg-slate-50 active:scale-95 flex items-center justify-center gap-2 shadow-sm"
                        >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                            Sample
                        </button>
                        <input type="file" accept=".csv" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            disabled={isLocked || isImporting}
                            className="flex-[2] sm:flex-none px-8 py-3 bg-slate-900 text-white rounded-xl font-semibold text-[10px] uppercase tracking-widest transition-all hover:bg-black active:scale-95 disabled:opacity-30 flex items-center justify-center gap-2 shadow-lg"
                        >
                            {isImporting ? 'Syncing...' : 'Upload Registry'}
                        </button>
                    </div>
                    <p className="hidden sm:block text-[8px] text-slate-300 font-medium uppercase tracking-widest">Supports CSV Import: Truck,Trailer</p>
                </div>
            </div>

            {/* FLEXIBLE CONTENT SECTION */}
            <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-4 sm:gap-8 min-h-0">
                {/* TRUCK MANAGEMENT COLUMN */}
                <div className="flex flex-col min-h-0 bg-white rounded-[1.5rem] border border-slate-100 shadow-sm overflow-hidden">
                    <div className="p-5 border-b border-slate-50 bg-slate-50/50 shrink-0">
                        <div className="flex items-center justify-between mb-4">
                            <span className="text-[10px] font-semibold text-slate-400 uppercase tracking-widest">Primary Assets (Horses)</span>
                            <span className="text-[10px] font-medium text-slate-300 uppercase tracking-tighter">{validationLists.trucks.length} Units</span>
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                placeholder="New Reg Number..." 
                                className="flex-1 px-4 py-3 bg-white border border-slate-200 rounded-xl text-sm font-medium uppercase outline-none focus:ring-4 focus:ring-indigo-50/50 transition-all placeholder:text-slate-300 placeholder:font-normal" 
                                value={newTruck} 
                                onChange={e => setNewTruck(e.target.value)} 
                            />
                            <button 
                                onClick={() => handleAddAsset('truck')} 
                                disabled={isSubmitting || !newTruck.trim() || isLocked} 
                                className="px-6 py-3 bg-slate-900 hover:bg-black text-white rounded-xl font-semibold text-[10px] uppercase tracking-widest transition-all active:scale-95 disabled:opacity-30 shrink-0"
                            >
                                Add
                            </button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto scrollbar-hide">
                        <div className="divide-y divide-slate-50">
                            {validationLists.trucks.length === 0 ? (
                                <div className="p-12 text-center text-[10px] font-medium text-slate-300 uppercase tracking-widest italic">No assets registered</div>
                            ) : (
                                validationLists.trucks.map((t, i) => (
                                    <div key={i} className="px-6 py-3.5 flex items-center justify-between hover:bg-slate-50/50 transition-colors group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-1.5 h-1.5 rounded-full bg-slate-100 group-hover:bg-indigo-400 transition-colors"></div>
                                            <span className="text-sm font-medium text-slate-600 group-hover:text-slate-900 transition-colors">{t}</span>
                                        </div>
                                        <span className="text-[8px] font-bold text-slate-200 uppercase tracking-tighter opacity-0 group-hover:opacity-100 transition-opacity">Asset ID: {i+1}</span>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </div>

                {/* TRAILER MANAGEMENT COLUMN */}
                <div className="flex flex-col min-h-0 bg-white rounded-[1.5rem] border border-slate-100 shadow-sm overflow-hidden">
                    <div className="p-5 border-b border-slate-50 bg-slate-50/50 shrink-0">
                        <div className="flex items-center justify-between mb-4">
                            <span className="text-[10px] font-semibold text-slate-400 uppercase tracking-widest">Linked Equipment (Units)</span>
                            <span className="text-[10px] font-medium text-slate-300 uppercase tracking-tighter">{validationLists.trailers.length} Units</span>
                        </div>
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                placeholder="New Trailer ID..." 
                                className="flex-1 px-4 py-3 bg-white border border-slate-200 rounded-xl text-sm font-medium uppercase outline-none focus:ring-4 focus:ring-emerald-50/50 transition-all placeholder:text-slate-300 placeholder:font-normal" 
                                value={newTrailer} 
                                onChange={e => setNewTrailer(e.target.value)} 
                            />
                            <button 
                                onClick={() => handleAddAsset('trailer')} 
                                disabled={isSubmitting || !newTrailer.trim() || isLocked} 
                                className="px-6 py-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-semibold text-[10px] uppercase tracking-widest transition-all active:scale-95 disabled:opacity-30 shrink-0"
                            >
                                Add
                            </button>
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto scrollbar-hide">
                        <div className="divide-y divide-slate-50">
                            {validationLists.trailers.length === 0 ? (
                                <div className="p-12 text-center text-[10px] font-medium text-slate-300 uppercase tracking-widest italic">No trailers registered</div>
                            ) : (
                                validationLists.trailers.map((t, i) => (
                                    <div key={i} className="px-6 py-3.5 flex items-center justify-between hover:bg-slate-50/50 transition-colors group">
                                        <div className="flex items-center gap-3">
                                            <div className="w-1.5 h-1.5 rounded-full bg-slate-100 group-hover:bg-emerald-400 transition-colors"></div>
                                            <span className="text-sm font-medium text-slate-600 group-hover:text-slate-900 transition-colors">{t}</span>
