                        >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                            Export
                        </button>
                        <input type="file" accept=".csv" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            disabled={isLocked || isImporting}
                            className="flex-[2] sm:flex-none px-8 py-3 bg-slate-900 text-white rounded-xl font-medium text-[10px] uppercase tracking-widest transition-all hover:bg-black active:scale-95 disabled:opacity-30 flex items-center justify-center gap-2 shadow-lg"
