                    <svg className="w-3.5 h-3.5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                    <input 
                        type="text" 
                        placeholder="Search logs..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full sm:w-60 pl-9 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-[11px] outline-none font-normal focus:ring-4 focus:ring-indigo-50/50 transition-all"
                    />
                  </div>
              </div>

              <div className="flex-1 overflow-hidden">
                {isLoadingHistory ? (
                    <div className="py-24 text-center">
                        <div className="w-8 h-8 border-4 border-slate-100 border-t-slate-900 rounded-full animate-spin mx-auto mb-4"></div>
                        <p className="text-[9px] font-semibold text-slate-300 uppercase tracking-[0.3em]">Downloading archive</p>
                    </div>
                ) : displayList.length === 0 ? (
                    <div className="py-24 text-center text-[10px] font-medium text-slate-300 uppercase tracking-[0.3em]">Archive is empty</div>
                ) : (
                    <div className="divide-y divide-slate-50">
                        {displayList.map((item, i) => (
                            <div key={i} className="flex flex-col sm:flex-row sm:items-center px-6 py-4 hover:bg-slate-50/50 transition-colors gap-4">
                                {/* Lead Info: Status & Identity */}
                                <div className="flex items-center gap-4 flex-1 min-w-0">
                                    <div className={`flex items-center justify-center w-10 h-10 rounded-xl text-sm font-black text-white shadow-sm shrink-0
                                        ${Number(item.rate) >= 4 ? 'bg-emerald-500' : Number(item.rate) === 3 ? 'bg-amber-500' : 'bg-rose-500'}
                                    `}>
                                        {item.rate}
                                    </div>
                                    <div className="min-w-0 flex-1">
                                        <div className="font-semibold text-slate-800 text-sm truncate uppercase tracking-tight">{item.truckNo}</div>
                                        <div className="text-[10px] text-slate-400 font-medium truncate uppercase tracking-wider">{item.trailerNo || 'Solo Unit'}</div>
                                    </div>
                                </div>

                                {/* Shared Data Block: Personnel & Time */}
                                <div className="grid grid-cols-2 sm:flex sm:items-center gap-4 sm:gap-10 shrink-0">
                                    <div className="flex items-center gap-3">
                                        <div className="w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center text-[9px] font-bold text-slate-400 border border-slate-200 uppercase shrink-0">
                                            {String(item.inspectedBy || '?').charAt(0)}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="text-[10px] font-bold text-slate-600 truncate">{item.inspectedBy}</div>
                                            <div className="text-[8px] text-slate-400 uppercase tracking-widest">Auditor</div>
                                        </div>
                                    </div>
                                    <div className="text-right sm:text-left">
                                        <div className="text-[10px] font-bold text-slate-600">{new Date(item.timestamp).toLocaleDateString()}</div>
                                        <div className="text-[8px] text-slate-400 uppercase tracking-widest">{new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                                    </div>
                                </div>

                                {/* Action */}
                                <div className="sm:ml-4 border-t sm:border-t-0 border-slate-50 pt-3 sm:pt-0 shrink-0">
                                    <button 
                                      onClick={() => onViewReport(item)}
                                      className="w-full sm:w-auto inline-flex items-center justify-center gap-2 px-6 py-2.5 text-[10px] font-bold text-indigo-600 bg-indigo-50 hover:bg-indigo-600 hover:text-white rounded-xl transition-all uppercase tracking-widest border border-indigo-100 shadow-sm"
                                    >
                                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                                        Inspect
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
              </div>
          </div>
      </div>
    );
};

export default DashboardTemplate;

import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus, InspectionItemConfig, ValidationLists, SystemSettings } from '../types';
import { INSPECTION_ITEMS, INSPECTION_CATEGORIES, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_CATEGORIES, ACID_INSPECTION_ITEMS, ACID_CATEGORIES, PETROLEUM_V2_ITEMS, PETROLEUM_V2_CATEGORIES, SECTIONS } from '../constants';
import CameraCapture from '../components/CameraCapture';
import SignaturePad from '../components/SignaturePad';
import StatusButton from '../components/ui/StatusButton';
import Input from '../components/ui/Input';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface InspectionFormViewProps {
    initialData: InspectionData;
    activeModule: string;
    validationLists: ValidationLists;
    settings: SystemSettings;
    onSaveDraft: (data: InspectionData) => void;
    onSubmit: (data: InspectionData) => void;
    onExit: () => void;
    submissionStatus: 'idle' | 'submitting' | 'success' | 'offline_saved';
    onViewReport: (data: InspectionData) => void;
}

const InspectionFormView: React.FC<InspectionFormViewProps> = ({ 
    initialData, activeModule, validationLists, onSaveDraft, onSubmit, onExit, submissionStatus
}) => {
    const [formData, setFormData] = useState<InspectionData & any>(initialData);
    const [currentSection, setCurrentSection] = useState(0);
    const [errors, setErrors] = useState<Record<string, boolean>>({});
    const [showDraftSaved, setShowDraftSaved] = useState(false);

    const updateField = (field: string, value: any) => {
        setFormData((prev: any) => ({ ...prev, [field]: value }));
        if (errors[field]) {
            setErrors(prev => {
                const next = {...prev};
                delete next[field];
                return next;
            });
        }
    };

    const handleSaveDraftLocal = () => {
        onSaveDraft(formData);
        setShowDraftSaved(true);
        setTimeout(() => setShowDraftSaved(false), 2000);
    };

    const getItemsForStep = (stepIndex: number): InspectionItemConfig[] => {
        let categories: string[] = [];
        let sourceItems: InspectionItemConfig[] = [];

        if (activeModule === 'general') sourceItems = INSPECTION_ITEMS;
        else if (activeModule === 'petroleum') sourceItems = PETROLEUM_INSPECTION_ITEMS;
        else if (activeModule === 'petroleum_v2') sourceItems = PETROLEUM_V2_ITEMS;
        else if (activeModule === 'acid') sourceItems = ACID_INSPECTION_ITEMS;

        if (activeModule === 'general') {
            if (stepIndex === 2) categories = [INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION];
            if (stepIndex === 3) categories = [INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL];
            if (stepIndex === 4) categories = [INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER];
        } else if (activeModule === 'petroleum') {
            if (stepIndex === 2) categories = [PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT];
            if (stepIndex === 3) categories = [PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID];
            if (stepIndex === 4) categories = [PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD];
        } else if (activeModule === 'petroleum_v2') {
            if (stepIndex === 2) categories = [PETROLEUM_V2_CATEGORIES.PRIME_MOVER];
            if (stepIndex === 3) categories = [PETROLEUM_V2_CATEGORIES.TRAILER_TANKS];
            if (stepIndex === 4) categories = [PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS];
        } else if (activeModule === 'acid') {
            if (stepIndex === 2) categories = [ACID_CATEGORIES.PPE];
            if (stepIndex === 3) categories = [ACID_CATEGORIES.VEHICLE];
            if (stepIndex === 4) categories = [ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION];
        }

        return sourceItems.filter(item => categories.includes(item.category));
    };

    const validateSection = (sectionIndex: number): boolean => {
        const newErrors: Record<string, boolean> = {};

        if (sectionIndex === 0) {
            if (!formData.truckNo) newErrors.truckNo = true;
            if (!formData.trailerNo) newErrors.trailerNo = true;
            if (!formData.driverName) newErrors.driverName = true;
            if (!formData.location) newErrors.location = true;
            if (!formData.odometer) newErrors.odometer = true;
            if (activeModule !== 'general' && !formData.jobCard) newErrors.jobCard = true;
        }

        if (sectionIndex >= 2 && sectionIndex <= 4) {
            const requiredItems = getItemsForStep(sectionIndex);
            requiredItems.forEach(item => {
                if (!formData[item.id]) newErrors[item.id] = true;
            });
        }

        if (sectionIndex === 5) {
             if (!formData.remarks || formData.remarks.trim() === '') newErrors.remarks = true;
             if (!formData.rate || formData.rate === 0) newErrors.rate = true;
             if (!formData.inspectorSignature) newErrors.inspectorSignature = true;
             if (!formData.driverSignature) newErrors.driverSignature = true;
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            window.scrollTo({ top: 0, behavior: 'smooth' }); 
            return false;
        }

        setErrors({});
        return true;
    };

    const handleNext = () => {
        if (!validateSection(currentSection)) return;
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setCurrentSection(prev => Math.min(prev + 1, SECTIONS.length - 1));
    };

    const handleBack = () => {
        if (currentSection === 0) onExit();
        else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
            setCurrentSection(prev => Math.max(prev - 1, 0));
        }
    };

    const handleSubmitInspection = () => {
        if (validateSection(currentSection)) onSubmit(formData);
    };

    return (
        <div className="flex flex-col min-h-[calc(100vh-56px)] bg-slate-50/50">
             {/* COMPACT FLOW INDICATOR */}
             <div className="bg-white border-b border-slate-100 sticky top-14 z-30 shadow-sm shrink-0">
                <div className="max-w-5xl mx-auto px-4 py-4 sm:py-5 overflow-hidden">
                    <div className="flex justify-between items-center gap-1 sm:gap-4">
                        {SECTIONS.map((section, idx) => {
                            const isActive = idx === currentSection;
                            const isCompleted = idx < currentSection;
                            return (
                                <React.Fragment key={section.id}>
                                    <div className="flex flex-col items-center gap-1.5 min-w-0 transition-all duration-500">
                                        <div className={`
                                            w-6 h-6 sm:w-8 sm:h-8 rounded-lg flex items-center justify-center text-[8px] sm:text-xs font-black transition-all
                                            ${isActive ? 'bg-slate-900 text-white shadow-lg scale-110' : isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-300'}
                                        `}>
                                            {isCompleted ? '✓' : idx + 1}
                                        </div>
                                        <span className={`text-[7px] font-black uppercase tracking-tighter sm:tracking-widest truncate w-full text-center hidden xs:block ${isActive ? 'text-slate-900' : 'text-slate-300'}`}>
                                            {section.title}
                                        </span>
                                    </div>
                                    {idx < SECTIONS.length - 1 && (
                                        <div className={`h-px flex-1 rounded-full ${isCompleted ? 'bg-emerald-500' : 'bg-slate-100'}`} />
                                    )}
                                </React.Fragment>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* FLUID CONTENT AREA */}
            <div className="flex-1 p-4 sm:p-8 w-full max-w-5xl mx-auto pb-32">
                {currentSection === 0 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Audit Parameters</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 sm:gap-8">
                                <AutocompleteInput label="Horse Reg No *" value={formData.truckNo} onChange={v => updateField('truckNo', v)} options={validationLists.trucks} isRegNo={true} error={errors.truckNo} />
                                <AutocompleteInput label="Trailer ID *" value={formData.trailerNo} onChange={v => updateField('trailerNo', v)} options={validationLists.trailers} isRegNo={true} error={errors.trailerNo} />
                                <Input label="Job Card Reference" value={formData.jobCard || ''} onChange={v => updateField('jobCard', v)} error={errors.jobCard} />
                                <AutocompleteInput label="Auditor (Verified)" value={formData.inspectedBy} onChange={v => updateField('inspectedBy', v)} options={validationLists.inspectors} readOnly={true} />
                                <AutocompleteInput label="Operator Name *" value={formData.driverName} onChange={v => updateField('driverName', v)} options={validationLists.drivers} isTitleCase={true} error={errors.driverName} />
                                <AutocompleteInput label="Hub Location *" value={formData.location} onChange={v => updateField('location', v)} options={validationLists.locations} isTitleCase={true} error={errors.location} />
                                <Input label="Odometer Reading (KM) *" type="number" value={formData.odometer} onChange={v => updateField('odometer', v)} error={errors.odometer} />
                            </div>
                        </div>
                    </div>
                )}

                {currentSection === 1 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Visual Audit Logs</h2>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                                <CameraCapture label="Horse: Front Aspect" existingImage={formData.photoFront} onCapture={img => updateField('photoFront', img)} />
                                <CameraCapture label="Horse: Left Elevation" existingImage={formData.photoLS} onCapture={img => updateField('photoLS', img)} />
                                <CameraCapture label="Horse: Right Elevation" existingImage={formData.photoRS} onCapture={img => updateField('photoRS', img)} />
                                <CameraCapture label="Trailer: Rear Aspect" existingImage={formData.photoBack} onCapture={img => updateField('photoBack', img)} />
                            </div>
                        </div>
                    </div>
                )}

                {(currentSection >= 2 && currentSection <= 4) && (
                    <div className="space-y-6 animate-fadeIn">
                        {Array.from(new Set(getItemsForStep(currentSection).map(i => i.category))).map(cat => (
                            <div key={cat} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
                                <div className="bg-slate-50/50 px-6 py-4 border-b border-slate-100 flex justify-between items-center">
                                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{cat}</h3>
                                </div>
                                <div className="divide-y divide-slate-50">
                                    {getItemsForStep(currentSection).filter(i => i.category === cat).map(item => (
                                        <div key={item.id} className={`p-6 sm:p-8 transition-colors ${errors[item.id] ? 'bg-rose-50/30' : ''}`}>
                                            <p className="font-bold text-xs sm:text-sm text-slate-700 uppercase tracking-tight mb-5 leading-snug">{item.label}</p>
                                            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 sm:gap-4 max-w-2xl">
                                                <StatusButton label="Good" status={InspectionStatus.GOOD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.GOOD)} colorClass="green" />
                                                <StatusButton label="Bad" status={InspectionStatus.BAD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.BAD)} colorClass="red" />
                                                <StatusButton label="Needs Attn" status={InspectionStatus.ATTENTION} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.ATTENTION)} colorClass="yellow" />
                                                <StatusButton label="N/A" status={InspectionStatus.NIL} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.NIL)} colorClass="gray" />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {currentSection === 5 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Final Authorization</h2>
                            <div className="space-y-8">
                                <div>
                                    <label className="block text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest">Findings & Remarks *</label>
                                    <textarea className="w-full p-6 bg-slate-50 border border-slate-100 rounded-2xl h-40 outline-none font-medium text-sm focus:ring-4 focus:ring-indigo-50/50 resize-none transition-all" value={formData.remarks} onChange={e => updateField('remarks', e.target.value)} />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">Safety Performance Rating *</label>
                                    <div className="flex gap-2 sm:gap-4">
                                        {[1, 2, 3, 4, 5].map(num => (
                                            <button key={num} onClick={() => updateField('rate', num)} className={`flex-1 h-12 sm:h-14 rounded-xl font-black text-lg transition-all ${formData.rate === num ? 'bg-slate-900 text-white shadow-lg scale-105' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}>{num}</button>
                                        ))}
                                    </div>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6 border-t border-slate-50">
                                    <SignaturePad label="Auditor Authentication" existingSignature={formData.inspectorSignature} onSave={sig => updateField('inspectorSignature', sig)} />
                                    <SignaturePad label="Operator Confirmation" existingSignature={formData.driverSignature} onSave={sig => updateField('driverSignature', sig)} />
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {currentSection === 6 && (
                    <div className="animate-fadeIn py-10 text-center">
                        <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-8 border border-emerald-100">
                            <svg className="w-10 h-10 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                        </div>
                        <h2 className="text-3xl font-black text-slate-800 mb-4 uppercase tracking-tight">Audit Finalized</h2>
                        <p className="text-slate-400 font-medium text-sm max-w-sm mx-auto leading-relaxed mb-12">All mandatory safety parameters have been validated. Transmitting data to secure corporate repository.</p>
                        <button 
                            onClick={handleSubmitInspection} 
                            disabled={submissionStatus !== 'idle'} 
                            className="w-full sm:w-auto px-12 py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black text-sm shadow-2xl transition-all flex items-center justify-center gap-3 active:scale-95 border-t border-white/10 uppercase tracking-[0.2em]"
                        >
                            {submissionStatus === 'submitting' ? 'Uploading...' : 'Synchronize Audit'}
                        </button>
                    </div>
                )}
            </div>

            {/* ADAPTIVE FOOTER NAV */}
            <footer className="bg-white/90 backdrop-blur-md border-t border-slate-100 p-4 sm:p-6 fixed bottom-0 left-0 right-0 z-40 pb-[max(1rem,env(safe-area-inset-bottom))]">
                <div className="max-w-5xl mx-auto flex gap-3 sm:gap-6">
                    <button onClick={handleBack} className="flex-1 sm:flex-none px-6 sm:px-10 py-3.5 rounded-xl sm:rounded-2xl border border-slate-200 font-black text-slate-400 hover:text-slate-800 transition-all text-[10px] uppercase tracking-widest active:scale-95">
                        {currentSection === 0 ? 'Abort' : 'Previous'}
                    </button>
                    <div className="flex gap-3 flex-[2] sm:flex-1 justify-end">
                        <button onClick={handleSaveDraftLocal} className="flex-1 sm:flex-none px-4 sm:px-8 py-3.5 rounded-xl sm:rounded-2xl bg-indigo-50 text-indigo-600 font-black hover:bg-indigo-100 transition-all flex items-center justify-center gap-2 text-[10px] uppercase tracking-widest active:scale-95">
                            {showDraftSaved ? 'Locked' : 'Draft'}
                        </button>
                        {currentSection < SECTIONS.length - 1 && (
                            <button onClick={handleNext} className="flex-[1.5] sm:flex-none px-8 sm:px-12 py-3.5 rounded-xl sm:rounded-2xl bg-slate-900 text-white font-black hover:bg-black shadow-lg transition-all flex items-center justify-center gap-3 text-[10px] uppercase tracking-[0.2em] active:scale-95 border-t border-white/10">
                                Continue
                                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                            </button>
                        )}
                    </div>
                </div>
            </footer>
        </div>
    );
};

export default InspectionFormView;

import React from 'react';
import { InspectionStatus } from '../../types';

const StatusButton: React.FC<{label: string, status: InspectionStatus, current: any, onClick: () => void, colorClass: 'green' | 'red' | 'yellow' | 'gray'}> = ({label, status, current, onClick, colorClass}) => {
  const isSelected = status === current;
  const colors = {
    green: isSelected ? 'bg-emerald-600 text-white border-emerald-600 shadow-lg shadow-emerald-100' : 'bg-white text-emerald-700 border-emerald-100 hover:bg-emerald-50',
    red: isSelected ? 'bg-rose-600 text-white border-rose-600 shadow-lg shadow-rose-100' : 'bg-white text-rose-700 border-rose-100 hover:bg-rose-50',
    yellow: isSelected ? 'bg-amber-500 text-white border-amber-500 shadow-lg shadow-amber-100' : 'bg-white text-amber-600 border-amber-100 hover:bg-amber-50',
    gray: isSelected ? 'bg-slate-700 text-white border-slate-700 shadow-lg shadow-slate-100' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50',
  };

  return (
    <button 
      onClick={onClick} 
      className={`relative py-3 px-1 rounded-xl border font-black text-[9px] transition-all flex flex-col items-center justify-center gap-1.5 flex-1 min-w-0 ${colors[colorClass]} ${isSelected ? 'z-10 scale-[1.02]' : 'shadow-sm opacity-90 hover:opacity-100 hover:scale-[1.01]'}`}
    >
      <div className="h-4 flex items-center justify-center pointer-events-none scale-90 sm:scale-100">
        {status === InspectionStatus.GOOD && <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M5 13l4 4L19 7"></path></svg>}
        {status === InspectionStatus.BAD && <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12"></path></svg>}
        {status === InspectionStatus.ATTENTION && <span className="text-sm font-black italic">!</span>}
        {status === InspectionStatus.NIL && <span className="text-sm font-black opacity-40">Ø</span>}
      </div>
      <span className="uppercase tracking-tighter sm:tracking-widest truncate w-full px-1 text-center pointer-events-none">
        {label}
      </span>
    </button>
  );
};

export default StatusButton;

import React, { useState, useMemo } from 'react';
import { InspectionData } from '../../types';
import SubscriptionLock from '../ui/SubscriptionLock';

interface DashboardTemplateProps {
    title: string;
    description: string;
    icon: React.ReactNode;
    colorTheme: 'emerald' | 'orange' | 'rose' | 'purple' | 'blue' | 'slate';
    stats: { total: number, passRate: number | string };
    startNewInspection: () => void;
    fetchHistory: (force?: boolean) => void;
    isLoadingHistory: boolean;
    historyList: InspectionData[];
    onViewReport: (item: InspectionData) => void;
    onPrint: (item: InspectionData) => void;
    userRole?: string;
    titlePrefix?: string;
    isLocked?: boolean;
    lockReason?: 'maintenance' | 'license';
    maintenanceMessage?: string;
}

const DashboardTemplate: React.FC<DashboardTemplateProps> = ({ 
    title, description, icon, stats, 
    startNewInspection, fetchHistory, isLoadingHistory, historyList, 
    onViewReport, userRole,
    isLocked = false,
    lockReason = 'license',
    maintenanceMessage
}) => {
    const [searchTerm, setSearchTerm] = useState('');

    const displayList = useMemo(() => {
        let list = historyList;
        if (searchTerm.trim()) {
            const lowerSearch = searchTerm.toLowerCase();
            list = list.filter(item => 
                (item.truckNo && item.truckNo.toLowerCase().includes(lowerSearch)) ||
                (item.driverName && item.driverName.toLowerCase().includes(lowerSearch)) ||
                (item.inspectedBy && item.inspectedBy.toLowerCase().includes(lowerSearch))
            );
        } else {
            list = list.slice(0, 15);
        }
        return list;
    }, [historyList, searchTerm]);

    const isSuperAdmin = userRole === 'SuperAdmin';
    const canCreate = (userRole === 'Admin' || userRole === 'Inspector' || userRole === 'SuperAdmin') && !isLocked;

    return (
      <div className="max-w-5xl mx-auto space-y-6 animate-fadeIn py-1">
          <SubscriptionLock 
            isLocked={isLocked} 
            lockReason={lockReason} 
            maintenanceMessage={maintenanceMessage}
            isSuperAdmin={isSuperAdmin}
          >
              <div className="bg-white rounded-[2rem] p-6 sm:p-8 border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6 sm:gap-8">
                   <div className="flex-1 w-full">
                       <div className="flex items-center gap-3 mb-2">
                           <span className="p-2.5 rounded-2xl bg-slate-50 text-slate-600 shadow-inner">{icon}</span>
                           <h2 className="text-xl sm:text-2xl font-medium text-slate-800 tracking-tight uppercase">{title}</h2>
                       </div>

                       <div className="flex flex-col sm:flex-row gap-3 mt-6">
                           {canCreate && (
                               <button 
                                 onClick={startNewInspection}
                                 className="px-7 py-3.5 bg-slate-900 hover:bg-black text-white text-[10px] font-black rounded-2xl transition-all flex items-center justify-center gap-3 uppercase tracking-[0.2em] shadow-lg active:scale-95 border-t border-white/10"
                               >
                                   <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 4v16m8-8H4"></path></svg>
                                   Start Inspection
                               </button>
                           )}
                           <button 
                             onClick={() => fetchHistory(true)}
                             disabled={isLoadingHistory}
                             className="px-6 py-3.5 bg-white border border-slate-200 text-slate-500 text-[10px] font-bold rounded-2xl hover:bg-slate-50 transition-all flex items-center justify-center gap-2.5 uppercase tracking-widest active:scale-95 shadow-sm disabled:opacity-50"
                           >
                               <svg className={`w-4 h-4 ${isLoadingHistory ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                               Sync Hub
                           </button>
                       </div>
                   </div>

                   <div className="flex gap-3 sm:gap-5 w-full sm:w-auto">
                       <div className="flex-1 sm:flex-none bg-slate-50 rounded-[1.5rem] p-4 sm:p-5 text-center min-w-[90px] border border-slate-100 shadow-inner">
                           <div className="text-2xl sm:text-3xl font-medium text-slate-800 leading-none">{stats.total}</div>
                           <div className="text-[8px] sm:text-[9px] text-slate-400 uppercase font-medium tracking-[0.2em] mt-2">Logs</div>
                       </div>
                       <div className="flex-1 sm:flex-none bg-emerald-50 rounded-[1.5rem] p-4 sm:p-5 text-center min-w-[90px] border border-emerald-100 shadow-inner">
                           <div className="text-2xl sm:text-3xl font-medium text-emerald-600 leading-none">{stats.passRate}%</div>
                           <div className="text-[8px] sm:text-[9px] text-slate-400 uppercase font-medium tracking-[0.2em] mt-2">Pass</div>
                       </div>
                   </div>
              </div>
          </SubscriptionLock>

          <div className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden shadow-sm flex flex-col min-h-0">
              <div className="px-6 py-4 border-b border-slate-50 flex flex-col sm:flex-row justify-between items-center bg-slate-50/30 gap-4">
                  <div className="flex items-center gap-4 self-start">
                      <h3 className="text-[10px] font-semibold text-slate-400 uppercase tracking-[0.3em]">Audit Archive</h3>
                      {isLocked && (
                          <span className="text-[8px] font-black text-rose-600 bg-rose-50 px-2 py-0.5 rounded border border-rose-100 uppercase">View Only</span>
                      )}
                  </div>
                  <div className="relative w-full sm:w-auto">
                    <svg className="w-3.5 h-3.5 absolute left-3 top-1/2 -translate-y-1/2 text-slate-300 pointer-events-none" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                    <input 
                        type="text" 
                        placeholder="Search logs..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full sm:w-60 pl-9 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-[11px] outline-none font-normal focus:ring-4 focus:ring-indigo-50/50 transition-all"
                    />
                  </div>
              </div>

              <div className="flex-1 overflow-hidden">
                {isLoadingHistory ? (
                    <div className="py-24 text-center">
                        <div className="w-8 h-8 border-4 border-slate-100 border-t-slate-900 rounded-full animate-spin mx-auto mb-4"></div>
                        <p className="text-[9px] font-semibold text-slate-300 uppercase tracking-[0.3em]">Downloading archive</p>
                    </div>
                ) : displayList.length === 0 ? (
                    <div className="py-24 text-center text-[10px] font-medium text-slate-300 uppercase tracking-[0.3em]">Archive is empty</div>
                ) : (
                    <div className="divide-y divide-slate-50">
                        {displayList.map((item, i) => (
                            <div key={i} className="flex flex-col sm:flex-row sm:items-center px-6 py-4 hover:bg-slate-50/50 transition-colors gap-4">
                                {/* Lead Info: Status & Identity */}
                                <div className="flex items-center gap-4 flex-1 min-w-0">
                                    <div className={`flex items-center justify-center w-10 h-10 rounded-xl text-sm font-black text-white shadow-sm shrink-0
                                        ${Number(item.rate) >= 4 ? 'bg-emerald-500' : Number(item.rate) === 3 ? 'bg-amber-500' : 'bg-rose-500'}
                                    `}>
                                        {item.rate}
                                    </div>
                                    <div className="min-w-0 flex-1">
                                        <div className="font-semibold text-slate-800 text-sm truncate uppercase tracking-tight">{item.truckNo}</div>
                                        <div className="text-[10px] text-slate-400 font-medium truncate uppercase tracking-wider">{item.trailerNo || 'Solo Unit'}</div>
                                    </div>
                                </div>

                                {/* Shared Data Block: Personnel & Time */}
                                <div className="grid grid-cols-2 sm:flex sm:items-center gap-4 sm:gap-10 shrink-0">
                                    <div className="flex items-center gap-3">
                                        <div className="w-7 h-7 rounded-lg bg-slate-100 flex items-center justify-center text-[9px] font-bold text-slate-400 border border-slate-200 uppercase shrink-0">
                                            {String(item.inspectedBy || '?').charAt(0)}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="text-[10px] font-bold text-slate-600 truncate">{item.inspectedBy}</div>
                                            <div className="text-[8px] text-slate-400 uppercase tracking-widest">Auditor</div>
                                        </div>
                                    </div>
                                    <div className="text-right sm:text-left">
                                        <div className="text-[10px] font-bold text-slate-600">{new Date(item.timestamp).toLocaleDateString()}</div>
                                        <div className="text-[8px] text-slate-400 uppercase tracking-widest">{new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                                    </div>
                                </div>

                                {/* Action */}
                                <div className="sm:ml-4 border-t sm:border-t-0 border-slate-50 pt-3 sm:pt-0 shrink-0">
                                    <button 
                                      onClick={() => onViewReport(item)}
                                      className="w-full sm:w-auto inline-flex items-center justify-center gap-2 px-6 py-2.5 text-[10px] font-bold text-indigo-600 bg-indigo-50 hover:bg-indigo-600 hover:text-white rounded-xl transition-all uppercase tracking-widest border border-indigo-100 shadow-sm"
                                    >
                                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                                        Inspect
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
              </div>
          </div>
      </div>
    );
};

export default DashboardTemplate;

import React, { useState, useEffect } from 'react';
import { InspectionData, InspectionStatus, InspectionItemConfig, ValidationLists, SystemSettings } from '../types';
import { INSPECTION_ITEMS, INSPECTION_CATEGORIES, PETROLEUM_INSPECTION_ITEMS, PETROLEUM_CATEGORIES, ACID_INSPECTION_ITEMS, ACID_CATEGORIES, PETROLEUM_V2_ITEMS, PETROLEUM_V2_CATEGORIES, SECTIONS } from '../constants';
import CameraCapture from '../components/CameraCapture';
import SignaturePad from '../components/SignaturePad';
import StatusButton from '../components/ui/StatusButton';
import Input from '../components/ui/Input';
import AutocompleteInput from '../components/ui/AutocompleteInput';

interface InspectionFormViewProps {
    initialData: InspectionData;
    activeModule: string;
    validationLists: ValidationLists;
    settings: SystemSettings;
    onSaveDraft: (data: InspectionData) => void;
    onSubmit: (data: InspectionData) => void;
    onExit: () => void;
    submissionStatus: 'idle' | 'submitting' | 'success' | 'offline_saved';
    onViewReport: (data: InspectionData) => void;
}

const InspectionFormView: React.FC<InspectionFormViewProps> = ({ 
    initialData, activeModule, validationLists, onSaveDraft, onSubmit, onExit, submissionStatus
}) => {
    const [formData, setFormData] = useState<InspectionData & any>(initialData);
    const [currentSection, setCurrentSection] = useState(0);
    const [errors, setErrors] = useState<Record<string, boolean>>({});
    const [showDraftSaved, setShowDraftSaved] = useState(false);

    const updateField = (field: string, value: any) => {
        setFormData((prev: any) => ({ ...prev, [field]: value }));
        if (errors[field]) {
            setErrors(prev => {
                const next = {...prev};
                delete next[field];
                return next;
            });
        }
    };

    const handleSaveDraftLocal = () => {
        onSaveDraft(formData);
        setShowDraftSaved(true);
        setTimeout(() => setShowDraftSaved(false), 2000);
    };

    const getItemsForStep = (stepIndex: number): InspectionItemConfig[] => {
        let categories: string[] = [];
        let sourceItems: InspectionItemConfig[] = [];

        if (activeModule === 'general') sourceItems = INSPECTION_ITEMS;
        else if (activeModule === 'petroleum') sourceItems = PETROLEUM_INSPECTION_ITEMS;
        else if (activeModule === 'petroleum_v2') sourceItems = PETROLEUM_V2_ITEMS;
        else if (activeModule === 'acid') sourceItems = ACID_INSPECTION_ITEMS;

        if (activeModule === 'general') {
            if (stepIndex === 2) categories = [INSPECTION_CATEGORIES.PPE, INSPECTION_CATEGORIES.DOCUMENTATION];
            if (stepIndex === 3) categories = [INSPECTION_CATEGORIES.VEHICLE_EXTERIOR, INSPECTION_CATEGORIES.LIGHTS_ELECTRICAL];
            if (stepIndex === 4) categories = [INSPECTION_CATEGORIES.MECHANICAL, INSPECTION_CATEGORIES.TRAILER];
        } else if (activeModule === 'petroleum') {
            if (stepIndex === 2) categories = [PETROLEUM_CATEGORIES.TRUCK_EQUIPMENT];
            if (stepIndex === 3) categories = [PETROLEUM_CATEGORIES.TYRES, PETROLEUM_CATEGORIES.PPE_ID];
            if (stepIndex === 4) categories = [PETROLEUM_CATEGORIES.DOCUMENTS, PETROLEUM_CATEGORIES.ONBOARD];
        } else if (activeModule === 'petroleum_v2') {
            if (stepIndex === 2) categories = [PETROLEUM_V2_CATEGORIES.PRIME_MOVER];
            if (stepIndex === 3) categories = [PETROLEUM_V2_CATEGORIES.TRAILER_TANKS];
            if (stepIndex === 4) categories = [PETROLEUM_V2_CATEGORIES.DRIVER, PETROLEUM_V2_CATEGORIES.SAFETY_SIGNS, PETROLEUM_V2_CATEGORIES.DOCUMENTS];
        } else if (activeModule === 'acid') {
            if (stepIndex === 2) categories = [ACID_CATEGORIES.PPE];
            if (stepIndex === 3) categories = [ACID_CATEGORIES.VEHICLE];
            if (stepIndex === 4) categories = [ACID_CATEGORIES.SPILL_KIT, ACID_CATEGORIES.DOCUMENTATION];
        }

        return sourceItems.filter(item => categories.includes(item.category));
    };

    const validateSection = (sectionIndex: number): boolean => {
        const newErrors: Record<string, boolean> = {};

        if (sectionIndex === 0) {
            if (!formData.truckNo) newErrors.truckNo = true;
            if (!formData.trailerNo) newErrors.trailerNo = true;
            if (!formData.driverName) newErrors.driverName = true;
            if (!formData.location) newErrors.location = true;
            if (!formData.odometer) newErrors.odometer = true;
            if (activeModule !== 'general' && !formData.jobCard) newErrors.jobCard = true;
        }

        if (sectionIndex >= 2 && sectionIndex <= 4) {
            const requiredItems = getItemsForStep(sectionIndex);
            requiredItems.forEach(item => {
                if (!formData[item.id]) newErrors[item.id] = true;
            });
        }

        if (sectionIndex === 5) {
             if (!formData.remarks || formData.remarks.trim() === '') newErrors.remarks = true;
             if (!formData.rate || formData.rate === 0) newErrors.rate = true;
             if (!formData.inspectorSignature) newErrors.inspectorSignature = true;
             if (!formData.driverSignature) newErrors.driverSignature = true;
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            window.scrollTo({ top: 0, behavior: 'smooth' }); 
            return false;
        }

        setErrors({});
        return true;
    };

    const handleNext = () => {
        if (!validateSection(currentSection)) return;
        window.scrollTo({ top: 0, behavior: 'smooth' });
        setCurrentSection(prev => Math.min(prev + 1, SECTIONS.length - 1));
    };

    const handleBack = () => {
        if (currentSection === 0) onExit();
        else {
            window.scrollTo({ top: 0, behavior: 'smooth' });
            setCurrentSection(prev => Math.max(prev - 1, 0));
        }
    };

    const handleSubmitInspection = () => {
        if (validateSection(currentSection)) onSubmit(formData);
    };

    return (
        <div className="flex flex-col min-h-[calc(100vh-56px)] bg-slate-50/50">
             {/* COMPACT FLOW INDICATOR */}
             <div className="bg-white border-b border-slate-100 sticky top-14 z-30 shadow-sm shrink-0">
                <div className="max-w-5xl mx-auto px-4 py-4 sm:py-5 overflow-hidden">
                    <div className="flex justify-between items-center gap-1 sm:gap-4">
                        {SECTIONS.map((section, idx) => {
                            const isActive = idx === currentSection;
                            const isCompleted = idx < currentSection;
                            return (
                                <React.Fragment key={section.id}>
                                    <div className="flex flex-col items-center gap-1.5 min-w-0 transition-all duration-500">
                                        <div className={`
                                            w-6 h-6 sm:w-8 sm:h-8 rounded-lg flex items-center justify-center text-[8px] sm:text-xs font-black transition-all
                                            ${isActive ? 'bg-slate-900 text-white shadow-lg scale-110' : isCompleted ? 'bg-emerald-500 text-white' : 'bg-slate-100 text-slate-300'}
                                        `}>
                                            {isCompleted ? '✓' : idx + 1}
                                        </div>
                                        <span className={`text-[7px] font-black uppercase tracking-tighter sm:tracking-widest truncate w-full text-center hidden xs:block ${isActive ? 'text-slate-900' : 'text-slate-300'}`}>
                                            {section.title}
                                        </span>
                                    </div>
                                    {idx < SECTIONS.length - 1 && (
                                        <div className={`h-px flex-1 rounded-full ${isCompleted ? 'bg-emerald-500' : 'bg-slate-100'}`} />
                                    )}
                                </React.Fragment>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* FLUID CONTENT AREA */}
            <div className="flex-1 p-4 sm:p-8 w-full max-w-5xl mx-auto pb-32">
                {currentSection === 0 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Audit Parameters</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 sm:gap-8">
                                <AutocompleteInput label="Horse Reg No *" value={formData.truckNo} onChange={v => updateField('truckNo', v)} options={validationLists.trucks} isRegNo={true} error={errors.truckNo} />
                                <AutocompleteInput label="Trailer ID *" value={formData.trailerNo} onChange={v => updateField('trailerNo', v)} options={validationLists.trailers} isRegNo={true} error={errors.trailerNo} />
                                <Input label="Job Card Reference" value={formData.jobCard || ''} onChange={v => updateField('jobCard', v)} error={errors.jobCard} />
                                <AutocompleteInput label="Auditor (Verified)" value={formData.inspectedBy} onChange={v => updateField('inspectedBy', v)} options={validationLists.inspectors} readOnly={true} />
                                <AutocompleteInput label="Operator Name *" value={formData.driverName} onChange={v => updateField('driverName', v)} options={validationLists.drivers} isTitleCase={true} error={errors.driverName} />
                                <AutocompleteInput label="Hub Location *" value={formData.location} onChange={v => updateField('location', v)} options={validationLists.locations} isTitleCase={true} error={errors.location} />
                                <Input label="Odometer Reading (KM) *" type="number" value={formData.odometer} onChange={v => updateField('odometer', v)} error={errors.odometer} />
                            </div>
                        </div>
                    </div>
                )}

                {currentSection === 1 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Visual Audit Logs</h2>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 sm:gap-6">
                                <CameraCapture label="Horse: Front Aspect" existingImage={formData.photoFront} onCapture={img => updateField('photoFront', img)} />
                                <CameraCapture label="Horse: Left Elevation" existingImage={formData.photoLS} onCapture={img => updateField('photoLS', img)} />
                                <CameraCapture label="Horse: Right Elevation" existingImage={formData.photoRS} onCapture={img => updateField('photoRS', img)} />
                                <CameraCapture label="Trailer: Rear Aspect" existingImage={formData.photoBack} onCapture={img => updateField('photoBack', img)} />
                            </div>
                        </div>
                    </div>
                )}

                {(currentSection >= 2 && currentSection <= 4) && (
                    <div className="space-y-6 animate-fadeIn">
                        {Array.from(new Set(getItemsForStep(currentSection).map(i => i.category))).map(cat => (
                            <div key={cat} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
                                <div className="bg-slate-50/50 px-6 py-4 border-b border-slate-100 flex justify-between items-center">
                                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{cat}</h3>
                                </div>
                                <div className="divide-y divide-slate-50">
                                    {getItemsForStep(currentSection).filter(i => i.category === cat).map(item => (
                                        <div key={item.id} className={`p-6 sm:p-8 transition-colors ${errors[item.id] ? 'bg-rose-50/30' : ''}`}>
                                            <p className="font-bold text-xs sm:text-sm text-slate-700 uppercase tracking-tight mb-5 leading-snug">{item.label}</p>
                                            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 sm:gap-4 max-w-2xl">
                                                <StatusButton label="Good" status={InspectionStatus.GOOD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.GOOD)} colorClass="green" />
                                                <StatusButton label="Bad" status={InspectionStatus.BAD} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.BAD)} colorClass="red" />
                                                <StatusButton label="Needs Attn" status={InspectionStatus.ATTENTION} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.ATTENTION)} colorClass="yellow" />
                                                <StatusButton label="N/A" status={InspectionStatus.NIL} current={formData[item.id]} onClick={() => updateField(item.id, InspectionStatus.NIL)} colorClass="gray" />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {currentSection === 5 && (
                    <div className="space-y-4 animate-fadeIn">
                        <div className="bg-white p-6 sm:p-10 rounded-[2rem] border border-slate-100 shadow-sm">
                            <h2 className="text-xl sm:text-2xl font-black text-slate-800 mb-8 uppercase tracking-tight">Final Authorization</h2>
                            <div className="space-y-8">
                                <div>
                                    <label className="block text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest">Findings & Remarks *</label>
                                    <textarea className="w-full p-6 bg-slate-50 border border-slate-100 rounded-2xl h-40 outline-none font-medium text-sm focus:ring-4 focus:ring-indigo-50/50 resize-none transition-all" value={formData.remarks} onChange={e => updateField('remarks', e.target.value)} />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black uppercase text-slate-400 mb-4 tracking-widest">Safety Performance Rating *</label>
                                    <div className="flex gap-2 sm:gap-4">
                                        {[1, 2, 3, 4, 5].map(num => (
                                            <button key={num} onClick={() => updateField('rate', num)} className={`flex-1 h-12 sm:h-14 rounded-xl font-black text-lg transition-all ${formData.rate === num ? 'bg-slate-900 text-white shadow-lg scale-105' : 'bg-slate-50 text-slate-400 hover:bg-slate-100'}`}>{num}</button>
                                        ))}
                                    </div>
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-6 border-t border-slate-50">
                                    <SignaturePad label="Auditor Authentication" existingSignature={formData.inspectorSignature} onSave={sig => updateField('inspectorSignature', sig)} />
                                    <SignaturePad label="Operator Confirmation" existingSignature={formData.driverSignature} onSave={sig => updateField('driverSignature', sig)} />
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {currentSection === 6 && (
                    <div className="animate-fadeIn py-10 text-center">
                        <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-8 border border-emerald-100">
                            <svg className="w-10 h-10 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                        </div>
                        <h2 className="text-3xl font-black text-slate-800 mb-4 uppercase tracking-tight">Audit Finalized</h2>
                        <button 
                            onClick={handleSubmitInspection} 
                            disabled={submissionStatus !== 'idle'} 
                            className="w-full sm:w-auto px-12 py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black text-sm shadow-2xl transition-all flex items-center justify-center gap-3 active:scale-95 border-t border-white/10 uppercase tracking-[0.2em]"
                        >
                            {submissionStatus === 'submitting' ? 'Uploading...' : 'Submit'}
                        </button>
                    </div>
                )}
            </div>

            {/* ADAPTIVE FOOTER NAV */}
            <footer className="bg-white/90 backdrop-blur-md border-t border-slate-100 p-4 sm:p-6 fixed bottom-0 left-0 right-0 z-40 pb-[max(1rem,env(safe-area-inset-bottom))]">
                <div className="max-w-5xl mx-auto flex gap-3 sm:gap-6">
                    <button onClick={handleBack} className="flex-1 sm:flex-none px-6 sm:px-10 py-3.5 rounded-xl sm:rounded-2xl border border-slate-200 font-black text-slate-400 hover:text-slate-800 transition-all text-[10px] uppercase tracking-widest active:scale-95">
                        {currentSection === 0 ? 'Abort' : 'Previous'}
                    </button>
                    <div className="flex gap-3 flex-[2] sm:flex-1 justify-end">
                        <button onClick={handleSaveDraftLocal} className="flex-1 sm:flex-none px-4 sm:px-8 py-3.5 rounded-xl sm:rounded-2xl bg-indigo-50 text-indigo-600 font-black hover:bg-indigo-100 transition-all flex items-center justify-center gap-2 text-[10px] uppercase tracking-widest active:scale-95">
                            {showDraftSaved ? 'Locked' : 'Draft'}
                        </button>
                        {currentSection < SECTIONS.length - 1 && (
                            <button onClick={handleNext} className="flex-[1.5] sm:flex-none px-8 sm:px-12 py-3.5 rounded-xl sm:rounded-2xl bg-slate-900 text-white font-black hover:bg-black shadow-lg transition-all flex items-center justify-center gap-3 text-[10px] uppercase tracking-[0.2em] active:scale-95 border-t border-white/10">
                                Continue
                                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
                            </button>
                        )}
                    </div>
                </div>
            </footer>
        </div>
    );
};

