import React, { useEffect, useState } from 'react';
import { User } from '../types';

interface RequestTrackingViewProps {
    appScriptUrl: string;
    currentUser: User | null;
    showToast: (msg: string, type: 'success' | 'error' | 'info' | 'warning') => void;
    onRequestNew?: () => void;
}

interface RequestItem {
    id: string;
    requester: string;
    truck: string;
    trailer: string;
    type: string;
    reason: string;
    priority: string;
    assignedTo: string;
    status: string;
    timestamp: string;
}

const RequestTrackingView: React.FC<RequestTrackingViewProps> = ({ appScriptUrl, currentUser, showToast, onRequestNew }) => {
    const [requests, setRequests] = useState<RequestItem[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const isLocked = (window as any).isSubscriptionLocked || false;

    useEffect(() => {
        fetchRequests();
        const interval = setInterval(fetchRequests, 60000);
        return () => clearInterval(interval);
    }, [currentUser?.username, appScriptUrl]);

    const fetchRequests = async () => {
        if (!appScriptUrl || !currentUser) return;
        if (requests.length === 0) setIsLoading(true);

        try {
            const response = await fetch(`${appScriptUrl}?t=${new Date().getTime()}`);
            const json = await response.json();

            const reqSheet = json['Inspection_Requests'];
            if (reqSheet && Array.isArray(reqSheet) && reqSheet.length > 1) {
                const allMapped = reqSheet.slice(1)
                    .map((row: any[]) => ({
                        id: row[0],
                        requester: row[1],
                        truck: row[3],
                        trailer: row[4],
                        type: row[5],
                        reason: row[6],
                        priority: row[7],
                        assignedTo: row[8],
                        status: row[9] || 'Pending',
                        timestamp: row[10]
                    }));

                const filtered = allMapped.filter((req: RequestItem) => {
                    const role = currentUser.role.toLowerCase();
                    if (role === 'admin' || role === 'superadmin') return true;

                    const myName = String(currentUser.name || '').toLowerCase();
                    const isRequester = String(req.requester).toLowerCase() === myName;
                    const isAssigned = String(req.assignedTo).toLowerCase() === myName;
                    const isUnassigned = String(req.assignedTo).toLowerCase() === 'unassigned';

                    if (role === 'inspector') {
                        return isAssigned || isUnassigned || isRequester;
                    }
                    return isRequester;
                }).sort((a: RequestItem, b: RequestItem) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

                setRequests(filtered);
            } else {
                setRequests([]);
            }
        } catch (error) {
            console.error("Failed to fetch requests", error);
            if (requests.length === 0) showToast("Failed to load requests.", 'error');
        } finally {
            setIsLoading(false);
        }
    };

    const pendingCount = requests.filter(r => r.status === 'Pending').length;
    const completedCount = requests.filter(r => r.status === 'Completed').length;
    const completionRate = requests.length > 0 ? Math.round((completedCount / requests.length) * 100) : 0;

    return (
        <div className="max-w-6xl mx-auto space-y-6 animate-fadeIn px-2 sm:px-4 pb-20">
            {/* Clean Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 px-2">
                <div>
                    <h2 className="text-2xl sm:text-3xl font-medium text-slate-800 tracking-tight uppercase">Inspection Tracking</h2>
                    <p className="text-slate-400 font-medium mt-1 uppercase tracking-widest text-[9px]">Maintenance Pipeline</p>
                </div>
                {onRequestNew && (
                    <button 
                        onClick={onRequestNew}
                        disabled={isLocked}
                        className={`w-full sm:w-auto px-7 py-3.5 text-white font-semibold rounded-2xl shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2.5 text-[10px] uppercase tracking-widest
                            ${isLocked ? 'bg-slate-200 cursor-not-allowed text-slate-400 shadow-none' : 'bg-slate-900 hover:bg-black border-t border-white/10'}
                        `}
                    >
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M12 4v16m8-8H4"></path></svg>
                        New Request
                    </button>
                )}
            </div>

            {/* Subdued Metrics */}
            <div className="grid grid-cols-2 md:grid-cols-3 gap-3 sm:gap-6">
                <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Pending</p>
                    <h3 className="text-2xl font-semibold text-amber-500">{pendingCount}</h3>
                </div>
                <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Completed</p>
                    <h3 className="text-2xl font-semibold text-emerald-600">{completedCount}</h3>
                </div>
                <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm col-span-2 md:col-span-1">
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1.5">Progress</p>
                    <div className="flex items-center gap-3">
                        <h3 className="text-2xl font-semibold text-slate-700">{completionRate}%</h3>
                        <div className="flex-1 h-1.5 bg-slate-50 rounded-full overflow-hidden border border-slate-100">
                            <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${completionRate}%` }}></div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Unified Request List */}
            <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col">
                <div className="px-6 py-4 bg-slate-50/50 border-b border-slate-50">
                    <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">Active Requests</h3>
                </div>

                <div className="divide-y divide-slate-50">
                    {isLoading ? (
                        <div className="py-20 text-center">
                            <div className="w-8 h-8 border-4 border-slate-100 border-t-indigo-600 rounded-full animate-spin mx-auto mb-4"></div>
                            <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Updating data</p>
                        </div>
                    ) : requests.length === 0 ? (
                        <div className="py-20 text-center">
                            <p className="text-[11px] font-medium text-slate-300 uppercase tracking-widest">No active requests found</p>
                        </div>
                    ) : requests.map((req) => (
                        <div key={req.id} className="p-5 sm:px-8 sm:py-5 hover:bg-slate-50/50 transition-colors flex flex-col sm:flex-row sm:items-center gap-4 sm:gap-8">

                            {/* Lead Info: Status & Vehicle */}
                            <div className="flex items-center gap-4 flex-1 min-w-0">
                                <div className={`w-2 h-2 rounded-full shrink-0 ${req.status === 'Completed' ? 'bg-emerald-500' : 'bg-amber-400 animate-pulse'}`} />
                                <div className="min-w-0">
                                    <div className="text-sm font-semibold text-slate-800 uppercase tracking-tight truncate">{req.truck}</div>
                                    <div className="text-[10px] text-slate-400 font-medium uppercase tracking-wider">{req.trailer || 'Stand-alone Unit'}</div>
                                </div>
                            </div>

                            {/* Center Block: Task Detail */}
                            <div className="grid grid-cols-2 sm:flex sm:items-center gap-4 sm:gap-10 shrink-0">
                                <div className="min-w-[100px]">
                                    <div className="text-[11px] font-semibold text-slate-600 uppercase tracking-tight">{req.type}</div>
                                    <div className={`text-[9px] font-bold uppercase tracking-wider ${
                                        req.priority === 'Critical' || req.priority === 'Urgent' || req.priority === 'Safety Concern' ? 'text-rose-500' : 'text-slate-400'
                                    }`}>
                                        {req.priority} Priority
                                    </div>
                                </div>

                                <div className="min-w-[120px] text-right sm:text-left">
                                    <div className="flex items-center justify-end sm:justify-start gap-2">
                                        <div className="text-[11px] font-semibold text-slate-600 truncate max-w-[100px]">
                                            {req.assignedTo && req.assignedTo !== 'Unassigned' ? req.assignedTo : 'Unassigned'}
                                        </div>
                                    </div>
                                    <div className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">Inspector</div>
                                </div>
                            </div>

                            {/* End Block: Timestamp & Status Badge */}
                            <div className="flex items-center justify-between sm:justify-end gap-6 pt-3 sm:pt-0 border-t sm:border-t-0 border-slate-50">
                                <div className="text-left sm:text-right shrink-0">
                                    <div className="text-[11px] font-semibold text-slate-500">{new Date(req.timestamp).toLocaleDateString()}</div>
                                    <div className="text-[9px] text-slate-300 font-bold uppercase tracking-widest">{new Date(req.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                                </div>
                                <div className={`px-4 py-1.5 rounded-xl text-[9px] font-bold uppercase tracking-widest border shrink-0
                                    ${req.status === 'Completed' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-500 border-slate-200'}
                                `}>
                                    {req.status === 'Completed' ? 'Fulfilled' : 'Active'}
                                </div>
                            </div>

                        </div>
                    ))}
                </div>
            </div>

            <div className="text-center pt-2">
                <p className="text-[8px] text-slate-200 font-bold uppercase tracking-[0.4em]">Proprietary Pipeline Monitor v2.1</p>
            </div>
        </div>
    );
};

export default RequestTrackingView;

